INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('bbde0443-6bfd-5d71-ad92-61c418f2b20d', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli, eğitim sürecini yalnızca akademik başarı eksenli mekanik bir süreç olarak görmez. Bireyi; ahlaki, sosyal, duygusal, fiziksel ve zihinsel gelişim alanlarıyla bir bütün olarak değerlendirir. Eğitimi de sadece okul duvarları arasına sıkışmış bir olgu olmaktan çıkarıp, insanın tüm hayatına nüfuz eden çok boyutlu bir varoluşsal süreç olarak ele alır. Bu yaklaşım, modelin temel felsefesini oluşturan aşağıdaki kavramlardan hangisiyle doğrudan ifade edilmektedir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\TYMM-001 Konu Paketi.json (source id TYMM-000002)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('81f7e2a0-9b51-5b42-b5c4-acca5d5ecc24', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Bir lise müdürü, öğretim yılı başındaki öğretmenler kurulunda şu ifadeleri kullanmıştır: ''Sevgili meslektaşlarım, yetiştirdiğimiz öğrencilerin sadece evrensel düzeyde rekabet eden yetkinliklere sahip olması yetmez. Onlar, kendi kültürel hafızalarından beslenmeli, milletimizin tarihsel birikiminden ilham almalı ve bu kökler üzerinde durarak geleceği cesaretle inşa etmelidir.'' Okul müdürünün bu vurgusu, Türkiye Yüzyılı Maarif Modeli öğrenci profilindeki hangi temel bütünlük alanıyla doğrudan ilişkilidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\TYMM-001 Konu Paketi.json (source id TYMM-000003)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('996c4b63-fe56-5c07-a444-ce6d2fb1221b', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli Erdem-Değer-Eylem Çerçevesi, ahlaki gelişimi eylemler üzerinden inşa eder. Bu çerçevede, diğer tüm değerlerin etrafında kümelendiği, yoğun kesişim noktalarına sahip üç ana ''çatı değer'' belirlenmiştir. Aşağıdakilerden hangisi bu üç çatı değerin tamamını içermektedir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\TYMM-001 Konu Paketi.json (source id TYMM-000004)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('6123d014-91a7-5fd5-bba4-bf45e4b94b6e', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Erdem-Değer-Eylem Çerçevesi, değerlerin eyleme dönüşmesi sonucunda ulaşılmak istenen nihai hedefleri üç ana gelişim/etki alanı etrafında yapılandırmıştır. Modelin genel felsefesine göre, bireyin kendi özbenliği ile barışık olması (I), toplumsal birliğin çekirdeğinin güçlendirilmesi (II) ve doğayla uyumlu bir sürdürülebilirlik bilincinin kazanılması (III) hedeflerini yansıtan bu üç ana alan aşağıdakilerin hangisinde sırasıyla doğru verilmiştir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\TYMM-001 Konu Paketi.json (source id TYMM-000005)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('778a2f37-5589-5ecb-9e1d-7a3a27225869', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli, ulaşılması hedeflenen ''Yetkin ve Erdemli İnsan'' profili kapsamında öğrencinin çok yönlü özelliklere sahip olmasını bekler. Aşağıdaki davranışlardan hangisi modelde tanımlanan ''Bilge'' bir öğrencinin göstermesi beklenen özellikler arasında değerlendirilemez?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\TYMM-001 Konu Paketi.json (source id TYMM-000006)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('be89c726-dd77-55d6-9cb3-7573d85bb3f6', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Bir öğretmen derste öğrencilerine, karmaşık bir tarihî olayı anlatan uzun bir metin dağıtmış ve onlardan metindeki olayları oluşturan temel unsurları belirleyip bu unsurların birbirleriyle olan yapısal ilişkilerini ortaya çıkarmalarını istemiştir. Türkiye Yüzyılı Maarif Modeli Beceriler Çerçevesi dikkate alındığında, öğretmenin öğrencilerde öncelikle geliştirmeyi hedeflediği kavramsal beceri aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\TYMM-001 Konu Paketi.json (source id TYMM-000007)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('6051f79d-eaa2-5892-bbec-b37cd3339cee', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Fen bilimleri dersinde öğrenciler çevrelerindeki bitki türlerini incelemektedir. Bir öğrenci, incelediği bitkilerden çam ve kavağın yaprak yapıları ile gövde özelliklerindeki benzerlik ve farklılıkları listelemiş (I); ardından bu bitkileri, tohumlarının açıkta veya kapalı meyve içinde olmasına göre belirli etiketler altında gruplara ayırmıştır (II). Bu öğrencinin süreç içerisinde kullandığı kavramsal beceriler sırasıyla aşağıdakilerin hangisinde doğru verilmiştir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\TYMM-001 Konu Paketi.json (source id TYMM-000008)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('5471d1d8-3f05-5b4d-b8e2-82a2fa79edfd', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Sosyal-Duygusal Öğrenme (SDÖ) becerileri, bireyin grup içi dinamiklerde başarılı olmasını ve sosyal farkındalık geliştirmesini sağlar. Türkiye Yüzyılı Maarif Modeli''ne göre bir öğrencinin iletişim sırasında, ''başkaları konuşurken ne karşılık vereceğini düşünmekten ziyade ne söylendiğini anlamaya çalışması'' ve ''karşıdakinin sözünü bitirmesini sabırla beklemesi'' davranışları, aşağıdaki süreç bileşenlerinden hangisinin geliştiğini gösterir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\TYMM-001 Konu Paketi.json (source id TYMM-000009)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('e6b0998b-8e30-529d-ac17-235b6e366521', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Beceriler Çerçevesi''nde yer alan okuryazarlık becerileri, dijitalleşen dünyada öğrencilerin bilgiye erişim ve bilgiyi yönetme süreçlerini güvenli hale getirmeyi amaçlar. Buna göre, bir öğrencinin internet üzerindeki araştırma faaliyetlerinde kişisel verilerini korumaya özen göstermesi ve dijital platformlarda kendi mahremiyetini güvence altına alacak kalıcı adımlar atması, okuryazarlık alanındaki hangi alt beceriyle doğrudan ilgilidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\TYMM-001 Konu Paketi.json (source id TYMM-000010)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('40e4c4c0-3295-5d7f-9059-f93f08554ee8', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli öğretim programlarının dinamik yapısı; bilgi, beceri, değer ve eğilimler arasındaki anlamlı ağlara dayanır. Modelin sistematiğine göre, bir öğrencinin sahip olduğu kavramsal veya alan becerilerini gerçek yaşam problemlerinde kullanabilmesi için onu eyleme geçiren içsel hazırbulunuşluğu ve bilişsel alışkanlıkları ifade eden; yaşantılarda tüm becerilerin asıl ''tetikleyicisi'' olarak kabul edilen program ögesi aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\TYMM-001 Konu Paketi.json (source id TYMM-000011)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('a00d4206-f070-5614-a975-70f7f1321dec', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Sınıf öğretmeni Ayla Hanım, bir temayı işlerken sınıftaki öğrencilerin tümünün aynı performansla öğrenmediğini fark etmiştir. Bunun üzerine dersin işlenişi sırasında; kavramakta zorlanan bazı öğrenciler için konunun ana hatlarını içeren görsel şemalar ve ipuçları sunmuş, konuyu çok hızlı kavrayan bir grup öğrenci için ise aynı temanın günlük hayattaki uygulanabilirliği üzerine yaratıcı bir araştırma görevi tanımlamıştır. Ayla Hanım''ın kullandığı bu stratejiler, Türkiye Yüzyılı Maarif Modeli''nin farklılaştırılmış öğretim yaklaşımında sırasıyla hangi kavramlarla ifade edilir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\TYMM-001 Konu Paketi.json (source id TYMM-000012)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('a9cffb08-6da4-52a8-b07a-86f1eab17e7b', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Bir okul müdürü ders denetimi sırasında, İngilizce öğretmeninin dönem sonu değerlendirmesinde öğrencilere tek tip bir klasik sınav kâğıdı dağıtmak yerine; ''İsteyenler turistik bir bölge için İngilizce tanıtım broşürü hazırlayabilir, isteyenler kısa bir İngilizce tiyatro sahneleyebilir veya isteyenler de seçeceği bir konuda üç dakikalık bir podcast kaydedebilir.'' dediğini gözlemlemiştir. Öğretmenin bu uygulaması, Maarif Modeli''nin farklılaştırma ilkelerine göre öğretim sürecinin hangi boyutunda esneklik sağlandığını gösterir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\TYMM-001 Konu Paketi.json (source id TYMM-000013)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('b5f5d2de-029f-5867-b3a7-e52162cef5b6', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli''nin kapsayıcı eğitim anlayışı, ölçme ve değerlendirme süreçlerinin de öğrenmeyi dışlayan değil destekleyen bir yapıda kurgulanmasını gerektirir. Buna göre, Maarif Modeli''nin ölçme değerlendirme felsefesine uygun hareket eden bir öğretmenden aşağıdakilerden hangisini yapması beklenmez?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\TYMM-001 Konu Paketi.json (source id TYMM-000014)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('eae91ca9-10dc-5c19-87e7-7668de0c39e1', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli kapsamında ortaöğretim 9. ve 10. sınıflarda derse giren öğretmenlerin, her ünite veya tema bitiminde öğrencilerin kazanımlara ulaşma düzeyini belirten bir ''Gelişim Raporu'' doldurması kararlaştırılmıştır. Bu raporlama sürecinin dönem sonuna bırakılmayıp öğrenme süreciyle eş zamanlı yürütülmesinin temel pedagojik amacı aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\TYMM-001 Konu Paketi.json (source id TYMM-000015)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('5091b47b-c082-5eb4-bf62-af9ac6f8ad5b', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli, öğrenme yaşantılarının kurgulanmasında bilginin tek bir derse hapsedilmesine karşı çıkar. Öğrencilerden, yerel ve küresel bir probleme (örneğin kuraklık) çözüm ararken sadece fen bilimlerinin değil; matematik, teknoloji ve sosyal bilimlerin sunduğu verileri bir arada kullanmaları beklenir. Modelin bu beklentisi, öğretim süreçlerinde öncelikli olarak hangi öğrenme yaklaşımının benimsendiğini göstermektedir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\TYMM-001 Konu Paketi.json (source id TYMM-000016)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('8b08c485-3751-53fd-9380-54cede06e34b', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Milli Eğitim Bakanlığınca yürütülen öğretim programları eğitici eğitiminde bir uzman şu ifadeyi kullanmıştır: ''Maarif Modeli''nde bir kavram sadece tek bir sınıf düzeyinde verilip bırakılmaz; 3. sınıftan 8. sınıfa kadar giderek artan bir derinlikle tekrar ele alınır. Ancak bununla da kalınmaz, aynı eğitim yılı içerisinde fen bilimlerinde işlenen veri toplama süreci, matematik dersindeki istatistik kazanımlarıyla da eş güdümlü olarak verilir.'' Uzmanın bahsettiği konunun giderek derinleşmesi (I) ve farklı derslerin eş güdümlü işlenmesi (II) kavramları sırasıyla aşağıdakilerin hangisinde doğru adlandırılmıştır?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\TYMM-001 Konu Paketi.json (source id TYMM-000017)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('0dc3f607-e377-5cba-baf1-7edcf291d6ef', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli kapsamında hayata geçirilen yeniliklerden biri de öğrencilerin okula uyum süreçlerinin sadece birinci haftaya sıkıştırılmış bir uygulama olmaktan çıkarılmasıdır. ''Aile On Yılı'' projesiyle desteklenen bu yeni yaklaşımda, ailelerin çocuğun öğrenme yolculuğuna okul idaresi ve öğretmenle birlikte tüm yıl boyunca aktif olarak eşlik etmesi öngörülmektedir. Bu değişiklikle okul kültürü bağlamında ulaşılmak istenen temel felsefi hedef aşağıdakilerden hangisidir?', 'PUBLISHED')
