INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('d325e328-903b-57f7-856c-2e277fd3ec8f', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli''nin öğrenci merkezli ekosisteminde öğretmenin rolü yeniden tanımlanmıştır. Bilginin kolayca erişilebilir olduğu bu çağda, öğretmen sadece sınıfın önünde durup doğruları anlatan bir kaynak değildir. Öğretmen, öğrenme yaşantılarını öğrencilerin ilgi ve ihtiyaçlarına göre farklılaştıran, onlara kendi zihinsel yapılarını kurmaları için yol gösteren ve süreçteki uygulamalarını sürekli eleştirel gözle değerlendiren profesyonel bir aktördür. Bu bağlamda Maarif Modeli, öğretmeni öncelikli olarak hangi kavramlarla nitelendirmektedir?', 'PUBLISHED')
