INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('37cdc27e-8889-576c-b2ff-aadb779449fc', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Erdem-Değer-Eylem Çerçevesi''nin okullardaki uygulama pratiğiyle ilgili olarak aşağıda verilen ifadelerden hangisi Türkiye Yüzyılı Maarif Modeli''nin vizyonuyla bağdaşmaz?', 'PUBLISHED')
