INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('dcbe0e6e-dbc0-5a8c-b028-39b03cf336ee', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Eğitim bilimleri literatüründe bireyin gelişimi farklı boyutlarla incelenir. Türkiye Yüzyılı Maarif Modeli, öğrenci profilini yapılandırırken bireyin ahlaki farkındalık kazanmasını, estetik bir bakış açısı geliştirmesini ve öğrendiği değerleri soyut birer bilgi olmaktan çıkarıp günlük hayatta eyleme dökmesini hedefler. Sadece doğruyu bilmenin yetmediği, doğru eylemi sergileme iradesinin vurgulandığı bu bütünlük alanı aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
