INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('d851d47b-3f0a-5aef-b9a2-0ee6ce04c3bf', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli öğretim programlarının temel felsefesi, bireyin geçmişinden kopmadan geleceği inşa etmesini vurgular. ''Köklerden Geleceğe'' mottosuyla hareket eden ve eğitim yoluyla sadece çağa ayak uyduran değil, medeniyeti etkin olarak inşa eden şahsiyetler yetiştirmeyi amaçlayan bu yaklaşım, eğitim felsefesi akımlarından hangisinin izlerini güçlü bir şekilde taşımaktadır?', 'PUBLISHED')
