INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('fcea30cc-19fe-57d9-86f3-ccc1a7632475', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Erdem-Değer-Eylem (EDE) Çerçevesi''nde yer alan çatı değerlerden ''Adalet'', fırsat eşitliğini ve liyakati önemser. Bu bağlamda, okulunda bir proje ekibi oluşturmak isteyen yöneticinin aşağıdaki davranışlardan hangisini sergilemesi adalet değerinin ''liyakate önem vermek'' bileşeniyle doğrudan örtüşür?', 'PUBLISHED')
