INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('3d82b58e-1e5d-5a7e-a5d9-d5aa04127d4f', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Beceriler Çerçevesi''nde öğrencilerin olaylar, durumlar veya metinler arasındaki tutarsızlıkları belirlemesi ve bu tutarsızlığı düzeltmek için olası yolları araştırıp harekete geçmesi beklenmektedir. İki veya daha fazla durum arasındaki tutarsızlığı giderme çabası, aşağıdaki kavramsal becerilerden hangisiyle ifade edilir?', 'PUBLISHED')
