INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('651ea65f-dca8-5dbd-a8e3-8d27ca16efd6', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Farklılaştırılmış öğretim sürecinde bir öğretmen, dersinde konuyu hızlı kavrayan üstün potansiyelli öğrencileri için soyut kavramları derinleştirmekte, disiplinler arası karmaşık bağlantılar kurmakta ve müfredat dışındaki güncel konuları da öğrenme sürecine dâhil etmektedir. Öğretmenin bu uygulaması, farklılaştırmanın hangi boyutu kapsamında bir zenginleştirme faaliyetidir?', 'PUBLISHED')
