INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('bf3738c8-d131-50d7-8b9a-8a69a97259a1', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli''nin Sosyal-Duygusal Öğrenme (SDÖ) becerilerinde ''İletişim'' geniş bir yer tutar. Öğrencinin iletişim sırasında yaşanan fiziksel veya psikolojik kopuklukları fark edip bunları ortadan kaldırmak için plan yapması ve bu planı uygulaması, aşağıdaki süreç bileşenlerinden hangisinin göstergesidir?', 'PUBLISHED')
