INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('2f358e10-348e-5180-9569-e1e551b92ab2', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Erdem-Değer-Eylem Çerçevesi''nde ''İçsel ahenge sahip huzurlu insan'' etki alanına yönelik belirlenen değerler arasında bireyin hırs ve azim arasındaki farkı bilmesi, hedeflerine ulaşmak için disiplinli bir yol haritası çizmesi ve yenilgi karşısında tekrar deneme gücü bulması hedeflenmektedir. Bu eylem göstergeleri aşağıdaki değerlerden hangisiyle doğrudan ilişkilidir?', 'PUBLISHED')
