INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('963fd4a8-41e2-5cce-9c03-72fbcd832f79', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Veri okuryazarlığı becerileri kapsamında öğrencilerden araştırma süreçlerinde elde ettikleri sayısal veya nitel verileri anlamlı bir bütün hâline getirmeleri istenir. Bir öğrencinin topladığı sıcaklık verilerini, diğer insanların daha kolay anlayabilmesi için bir çizgi grafiği veya bölgesel sıcaklık haritası hâline getirmesi hangi süreç bileşeniyle ilgilidir?', 'PUBLISHED')
