INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('9c214a40-d890-58b9-ad93-a83bbd775594', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli ''Yetkin ve Erdemli İnsan'' profilinde yer alan özelliklerden biri de öğrencinin geleceğe yönelik hayaller kurması, öğrenmeye karşı istekli olması, sorunlara karşı yenilikçi ve yaratıcı çözümler geliştirebilmesidir. Verilen bu özellikler, öğrenci profilini oluşturan aşağıdaki alt niteliklerin hangisiyle ifade edilmektedir?', 'PUBLISHED')
