INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('05f4d710-be69-5bcc-8b71-5eaaef738a7c', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli öğretim programlarının temel yapısı; birbirinden bağımsız kopuk parçalar yerine, unsurların birbirini beslediği ''bütünleşik bir ağ'' olarak tasarlanmıştır. Bu dinamik yapı içerisinde, öğretim programlarını bir arada tutan ve öğrenme yaşantılarını şekillendiren temel dörtlü bileşen aşağıdakilerin hangisinde tam ve doğru olarak verilmiştir?', 'PUBLISHED')
