INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('76da26d2-74e0-5383-905b-34d0d75f0db8', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Öğrenci profilini dört temel bütünlük üzerinden ele alan Türkiye Yüzyılı Maarif Modeli, öğrencinin sadece zihinsel kapasitesiyle değil bedensel, ruhsal ve fiziksel sağlığıyla da yakından ilgilenir. Düzenli uyuyan, sağlıklı beslenen, bağımlılıklardan uzak durarak ruh-beden dengesini korumayı başaran bir öğrenci, aşağıdaki bütünlük alanlarından hangisini sağlamış olur?', 'PUBLISHED')
