INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('6706bd4f-2672-5372-bce1-1ae7a0a7d852', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli öğrenme yaşantılarında, öğrencilerin sadece ders kitabı üzerinden değil, çevrelerindeki gerçek dünya problemlerine (örneğin su kıtlığı veya enerji israfı) yenilikçi çözümler tasarlaması beklenir. Öğrencilerin fen, matematik ve teknoloji bilgilerini bütünleştirerek bu sorunlara yönelik özgün bir ürün (prototip) veya model ortaya koymasını hedefleyen pedagojik yaklaşım aşağıdakilerden hangisidir?', 'PUBLISHED')
