INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('96324cf1-c7fe-5fb8-b869-3e7da85b61a0', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Beceriler Çerçevesi''nde yer alan bir kavramsal beceride; öğrencinin merak ettiği konuyu tanımlaması, buna ilişkin anlamlı sorular sorması, bilgi toplaması, toplanan bilgilerin doğruluğunu değerlendirmesi ve bu bilgiler üzerinden çıkarım yapması süreci işletilir. Belirtilen bu süreç bileşenleri aşağıdaki kavramsal becerilerden hangisine aittir?', 'PUBLISHED')
