INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('2e2ee06d-2bc9-5302-b4dd-c43496d224a3', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Dijitalleşmenin eğitimdeki artan rolüyle birlikte okuryazarlık becerileri önem kazanmıştır. Bir öğrencinin proje ödevi için internette bulduğu farklı dijital kaynakları birbiriyle karşılaştırması, bilgileri sınıflandırması, elde ettiği bilgilerin güvenirliğini değerlendirmesi ve bu bilgiler üzerinden akıl yürüterek mantıksal bir çıkarım yapması, okuryazarlık becerilerinin hangi alt boyutuyla doğrudan ilgilidir?', 'PUBLISHED')
