INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('b39c27cc-bb85-5473-a3a2-ec6080bb08f3', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Erdem-Değer-Eylem Çerçevesi, ''Huzurlu Aile ve Toplum'' hedefine ulaşmak için ailenin önemini vurgular. Aile içinde iş birliği yapmanın gerekliliğini fark eden ve kendine düşen görevleri (örneğin odasını toplama, ev işlerinde ebeveynlerine destek olma) zamanında ve en iyi şekilde yerine getiren bir öğrenci, EDE çerçevesindeki hangi değeri eyleme dökmektedir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
