INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('a5ea2e7a-5865-579f-87c0-7bb9d8a080af', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'İçsel ahenge sahip huzurlu insan profilini destekleyen EDE Çerçevesi değerlerinden biri de öğrencinin görevlerini yerine getirmek için etkili bir yol haritası çizmesidir. Açık ve ulaşılabilir hedefler belirlemeyi, bu hedefler doğrultusunda zamanı etkili bir şekilde yönetmeyi ve gerektiğinde rotasını yeniden düzenlemeyi içeren bu değer aşağıdakilerden hangisidir?', 'PUBLISHED')
