INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('9fb51390-33d4-53d6-9fcf-5f58f0d4df18', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli öğrenci profilinde yer alan ''Sağlıklı'' olma durumu, bireyin sadece bedensel değil ruhsal sağlığını da merkeze alır. Düzenli uyuyan, dengeli beslenen, bağımlılık yapıcı maddelerden ve teknoloji bağımlılığından uzak durarak içsel huzurunu koruyan bir öğrenci, modelin temel aldığı aşağıdaki bütünlük alanlarından hangisini sağlamış kabul edilir?', 'PUBLISHED')
