INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('27f255f0-3ed3-5d66-a9b9-d508d324a7d1', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Sınıf öğretmeni Kemal Bey, farklılaştırma uygulamaları kapsamında dersinde konuyu kavramakta zorlanan öğrenciler için temel kavramları somutlaştırarak anlatırken; konu hakkında ön bilgisi yüksek olan öğrenciler için soyut kavramları derinleştirmekte ve müfredat dışı güncel disiplinler arası bağlantılar kurmaktadır. Kemal Bey''in üstün potansiyelli öğrencilere yönelik uyguladığı bu strateji, farklılaştırmanın hangi boyutunda yapılan bir işlemdir?', 'PUBLISHED')
