INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('e07db383-a83b-5e2e-b68c-04c39183f1ba', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Öğrenme için Evrensel Tasarım ilkelerini sınıfına entegre eden bir öğretmen, sınıfın fiziksel alanını yeniden düzenlemiştir. İş birlikli grup çalışmaları için hareketli masalar kullanırken, bireysel çalışmak isteyen veya dikkat dağınıklığı yaşayan öğrenciler için sınıfın bir köşesinde dış uyarıcılardan arındırılmış ''sessiz bir çalışma alanı'' oluşturmuştur. Bu uygulama, farklılaştırılmış öğretimin hangi öğesinde yapılan bir esnekliktir?', 'PUBLISHED')
