INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('603c608a-e00c-54be-af31-739229b6d6ce', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli''nin kapsayıcı ölçme ve değerlendirme yaklaşımı, geleneksel tek tip testlerin ötesine geçerek öğrencinin süreç içindeki gelişimini çok boyutlu izlemeyi hedefler. Buna göre, ''öğrenme kanıtlarına dayalı durum değerlendirmesi'' yapmak isteyen bir öğretmenin aşağıdaki araçlardan hangisini kullanması beklenmez?', 'PUBLISHED')
