INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('0a26da53-765d-53ac-911d-5fe7e2193de9', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli öğretim programlarında bilgi ve beceriler izole bir şekilde verilmez. Örneğin, 6. sınıf Fen Bilimleri dersinde ''yoğunluk'' konusu işlenirken, eş zamanlı olarak Matematik dersinde ''hacim'' ve ''oran-orantı'' konularının ele alınması sağlanır. Farklı disiplinlerin birbirini destekleyecek şekilde eş güdümlü olarak yapılandırılması program tasarımında hangi kavramla ifade edilir?', 'PUBLISHED')
