INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('ea23cd5a-d6b7-5ae8-8d67-04d589921416', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Modelin getirdiği en önemli yeniliklerden biri de öğrencilerin okul sınırları dışındaki toplumsal olaylara duyarlılık geliştirmelerini sağlamaktır. Yaşlıların ihtiyaçlarını karşılama, sokak hayvanlarını koruma veya yerel bir çevre sorununa çözüm üretme gibi faaliyetlerin salt ders dışı bir aktivite olmaktan çıkarılıp müfredatın ruhuna dâhil edildiği program bileşeni aşağıdakilerden hangisidir?', 'PUBLISHED')
