INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('c12026c9-0010-5ce1-9fe8-d88046e94f1d', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', '''Aile On Yılı'' vizyonu doğrultusunda güncellenen okula uyum eğitimleri, Türkiye Yüzyılı Maarif Modeli ile sadece eğitim-öğretim yılının ilk haftasıyla sınırlı kalmayıp tüm yıla yayılan yapılandırılmış bir sürece dönüştürülmüştür. Bu köklü değişikliğin arkasında yatan temel eğitim felsefesi aşağıdakilerden hangisidir?', 'PUBLISHED')
