INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('62bdd351-d007-56df-8327-b789827aea78', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Sosyal-Duygusal Öğrenme (SDÖ) becerileri içerisinde bireyin kendi iç dünyasını ve çevresiyle olan etkileşimini sağlıklı yönetmesi esastır. Bir öğrencinin hissettiği öfke veya mutluluğu beden diliyle uyumlu bir şekilde, bağlama uygun ve doğru zamanda açıklaması SDÖ''nün hangi süreç bileşeninin göstergesidir?', 'PUBLISHED')
