INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('34fddde4-cd75-57c9-936f-1e249ddb9451', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkçe dersinde bir metni okuyan öğrencinin, metnin özünü anlaması, anladıklarını mantıksal bir çerçevede ana hatlarıyla kısaltması ve hiçbir anlam bozulmasına yol açmadan kendi cümleleriyle yeniden ifade etmesi (yorumlaması) istenir. Bu süreç aşağıdaki kavramsal becerilerden hangisine karşılık gelmektedir?', 'PUBLISHED')
