INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('5e62a02c-3ed2-53dc-a5e4-8ea63df89112', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Beceriler Çerçevesi''nde yer alan bir bileşen, öğrencinin belirli bir davranışı sergilemeye yönelik sahip olduğu içsel yönelimi, motivasyonu ve bilişsel alışkanlığı ifade eder. Tüm becerilerin harekete geçmesinde ''tetikleyici'' rol üstlenen ve sadece bilmeyi değil yapmaya istekli olmayı da kapsayan bu yapısal unsur aşağıdakilerden hangisidir?', 'PUBLISHED')
