INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('2a57dd3e-6169-5d3d-9f24-8ff372b625de', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli''nde her dersin kendi doğasından kaynaklanan ve o disipline özgü olan beceriler tanımlanmıştır. Kavramsal becerileri de kapsayacak şekilde yapılandırılan, örneğin Sosyal Bilgiler dersindeki ''Zamanı algılama ve kronolojik düşünme'' veya Fen Bilimleri dersindeki ''Bilimsel sorgulama'' gibi üst yapıları ifade eden beceri grubu aşağıdakilerden hangisidir?', 'PUBLISHED')
