INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('0470cca9-dfeb-5658-b063-2a3d0b907533', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli öğrenci profilini oluşturan alt özelliklerden biri de ''Bilge'' olmaktır. Aşağıdakilerden hangisi bilge bir öğrencinin temel göstergeleri arasında yer almaz?', 'PUBLISHED')
