INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('3dc2e616-04e0-561d-820e-f4d9077ef4cf', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli Beceriler Çerçevesi''nde yer alan alan becerileri, izole bir yetkinlik kümesi olmaktan ziyade kapsayıcı bir çatı niteliği taşır. Buna göre modelin yaklaşımında, ''Alan Becerileri'' kavramının yapısal içeriği aşağıdakilerin hangisinde en doğru biçimde ifade edilmiştir?', 'PUBLISHED')
