INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('9bf361b7-b526-524d-a24f-16555bf1108f', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Bir tarih öğretmeni, öğrencilerinden inceledikleri tarihsel olayları zaman şeridi üzerine yerleştirmelerini, bu olayların kısa ve uzun vadeli sonuçlarını ardışık bir şekilde sıralamalarını istemiştir. Öğretmenin bu etkinlikle öğrencilerde geliştirmeyi amaçladığı Sosyal Bilimler Alan Becerisi aşağıdakilerden hangisidir?', 'PUBLISHED')
