INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('8a98d4bb-c342-5fc9-9cb4-3874f3bd4744', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Günümüz dünyasında karşılaşılan karmaşık problemleri parçalardan ziyade bir bütünlük içinde anlamak önem kazanmıştır. Bireylerin gerçek yaşamda var olan karmaşık yapıların parçalarını belirlemesi, bu bileşenleri çözümlemesi, sistem davranışlarını tahmin eden araçlar oluşturarak sistemdeki sorunlara eyleme dönüşen sürdürülebilir çözümler üretmesi, Maarif Modeli''ndeki hangi okuryazarlık türüyle ilişkilidir?', 'PUBLISHED')
