INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('e513a75d-3045-5ae8-a3e6-05960759e60b', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Öğretim programlarında yer verilen programlar arası bileşenler, öğretim sürecinin dinamik bir yapıda ilerlemesini sağlamakta ve eğitimin örtük hedeflerinin müfredata organik olarak nüfuz etmesine imkân tanımaktadır. Aşağıdakilerden hangisi Türkiye Yüzyılı Maarif Modeli''nde tanımlanan üç ana programlar arası bileşenden biri değildir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\TYMM-004 Konu Paketi.json (source id TYMM-000066)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('662e27d3-5250-5fc7-9e9f-c660e7beff67', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Bir öğrenci lise eğitimi boyunca harçlıklarının bir kısmını düzenli olarak biriktirmiş, gelir ve satın alma gücü arasında anlamlı bir ilişki kurarak bilinçli harcama alışkanlıkları geliştirmiş ve ilerleyen süreçte bu birikimlerini uygun tasarruf araçlarıyla değerlendirmeye başlamıştır. Bu öğrencinin sergilediği tutum, beceriler çerçevesindeki hangi okuryazarlık alanının doğrudan sonucudur?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
