INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('860c6afb-d713-517c-8ae6-bb2c8b23ea49', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Farklılaştırma sürecinde öğretmenin öğrencilere ne öğreteceğini, kavramların soyutluk derecesini ve müfredat dışı çeşitliliği ayarlaması esastır. Bir öğretmenin, dersindeki konuyu derinlemesine merak eden öğrencilerine o konuyla ilişkili ve müfredatta yer almayan güncel bir makaleyi okuma görevi vermesi, farklılaştırmanın hangi boyutuna ve stratejisine örnektir?', 'PUBLISHED')
