INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('ac95fb7e-f11e-5904-8c26-53633288dc67', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli Beceriler Çerçevesi''nde bir öğrencinin çeşitli olayları, durumları veya konuları derinlemesine araştırması; bunlar arasındaki ortak ve ortak olmayan özellikleri belirlemesi, örüntüleri listelemesi ve bu örüntüler üzerinden yeni bir önermede (yargıda) bulunması süreci, aşağıdaki kavramsal becerilerden hangisiyle ifade edilmektedir?', 'PUBLISHED')
