INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('d29acac0-5d98-5818-9b36-62204547a517', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Erdem-Değer-Eylem Çerçevesi''nin etki alanlarından biri olan ''Yaşanabilir Çevre'', doğayla uyum içinde olan ve ekolojik dengeye saygı duyan bir insan modelini hedefler. Sürdürülebilirlik yeterlilikleriyle büyük ölçüde örtüşen bu yaklaşıma göre, aşağıdaki öğrenci davranışlarından hangisinin EDE çerçevesinin vizyonuyla çeliştiği söylenebilir?', 'PUBLISHED')
