INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('caee174c-f6f1-5b37-a038-d5b5df8228d8', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Bir grup öğrenci, mahallelerindeki çocuk parkının bakımsızlığından rahatsız olmuş ve bu durumu düzeltmek için aralarında bir plan yapmıştır. Öğrenciler çevredekilerle sosyal temas kurarak durumu müzakere etmiş, gerekli temizlik araçlarını sağlamış ve parkta ortaklaşa bir temizlik ve onarım çalışması yürüterek fikirlerini eyleme dönüştürmüştür. Bu senaryoda öğrencilerin sergilediği temel Sosyal Bilimler Alan Becerisi aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
