INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('28f973dd-e181-5a89-a6e4-297e01cf5be0', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Okul-aile iş birliğini merkezine alan Türkiye Yüzyılı Maarif Modeli, aileyi değer inşasının temel bileşeni kabul eder. ''Huzurlu Aile ve Toplum'' etki alanında yer alan değerlerden biri de bireyin ailesiyle sevinç ve üzüntülerini paylaşması, ailede yaşanan problemlere ortak çözüm yolları üretmeye çalışması ve ebeveynlerine psikolojik destek sunmaya istekli olmasıdır. Bu davranış örüntüsü aşağıdaki değerlerden hangisiyle doğrudan ilişkilidir?', 'PUBLISHED')
