INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('cb020c0c-8abc-5e13-a1b6-a43d41035f3b', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli''nin ölçme ve değerlendirme yaklaşımında öğrenme süreci; tek bir yazılı sınavla verilen puana indirgenmez. Asıl önemli olan, öğrencilerin gelişim düzeylerinin süreç içinde toplanan öğrenme kanıtlarıyla (performans görevi, portfolyo vb.) çok boyutlu olarak belirlenmesidir. Eğitimde sadece sonuca değil sürece odaklanan ve öğrencinin öğrenme yolculuğundaki mesafesini ölçmeyi amaçlayan bu değerlendirme felsefesi hangi kavramla ifade edilmektedir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
