INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('a6ba8ce2-1ba0-5ad3-afae-ba20db3e18db', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Dijitalleşen dünyada bilgiyi doğru yönetmek hayati önem taşır. Bir öğrencinin araştırma yaparken karşılaştığı çok sayıdaki dijital bilgiyi sadece okuyup geçmek yerine, farklı kaynaklardan gelen bu bilgileri birbirleriyle karşılaştırması, zihninde sınıflandırması, hangisinin güvenilir olduğunu değerlendirmesi ve nihayetinde bu bilgilerden geçerli bir çıkarım yapması süreci hangi okuryazarlık alt becerisiyle ilgilidir?', 'PUBLISHED')
