INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('d4fc42d3-3bb0-52d0-b72f-133cd088675f', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Sosyal-Duygusal Öğrenme (SDÖ) Becerilerinin temel taşı olan ''Benlik Becerileri'', kişinin kendi duygularını ve kişisel kaynaklarını geliştirerek kullanabilmesini ifade eder. Türkiye Yüzyılı Maarif Modeli öğretim programlarında, benlik becerileri genel olarak üç alt süreç altında toplanmıştır. Aşağıdakilerden hangisi bu üç benlik becerisini eksiksiz olarak ifade eder?', 'PUBLISHED')
