INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('ecfb40f0-d896-576a-b83a-4dedf251f78a', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Farklılaştırılmış öğretim pratikleri oluşturulurken kullanılan temel bir ilke, öğrenme ortamında oluşabilecek engelleri sürecin en başında öngörmeyi ve materyalleri herkesin (üstün yetenekli, öğrenme güçlüğü çeken, fiziksel engelli vb.) erişimine açık, esnek yapıda tasarlamayı gerektirir. Modelde kapsayıcı eğitimin merkezinde yer alan bu kavramsal yaklaşım aşağıdakilerden hangisidir?', 'PUBLISHED')
