INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('9812e3ff-163f-59ca-9238-956b0c4fe5ef', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli''nin hedeflediği ''Yetkin ve Erdemli İnsan'' profilinde yer alan özelliklerden biri de öğrencinin inandığı değerler uğruna harekete geçme cesaretini göstermesi, karşılaştığı zorluklar ve engeller karşısında kendi öz denetimini sağlayarak sabırlı ve kararlı bir tutum sergilemesidir. Verilen bu nitelikler, öğrenci profilini oluşturan aşağıdaki özelliklerden hangisiyle örtüşmektedir?', 'PUBLISHED')
