INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('bae09993-53e5-55cd-93f1-46af691cf7cc', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli eğitim felsefesini ''Bütüncül Eğitim Yaklaşımı'' üzerine inşa etmiştir. Buna göre model, salt zihinsel bilgi yüklemeyi amaçlayan yaklaşımları reddederek eğitimin kapsamını genişletmiştir. Bütüncül eğitim yaklaşımının en temel dayanağı ve gerekçesi aşağıdakilerden hangisidir?', 'PUBLISHED')
