INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('3d2cbf74-7234-5cd2-b2ed-51e16857f5b1', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Derste tarihi bir mektubu inceleyen bir öğrencinin; mektubu kimin yazdığını tespit etmesi, metindeki bilgilerin tarafsızlığını veya sınırlılıklarını sorgulaması, elde ettiği kanıtların geçerliğini yorumlayarak çıkarımlarına dayalı bir sunum hazırlaması süreci, Sosyal Bilimler Alan Becerilerinden hangisinin uygulandığını gösterir?', 'PUBLISHED')
