INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('b553547f-bf3e-5c5c-9071-735a0013e883', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli kapsamında ölçme ve değerlendirme süreçleri, sadece öğrenci başarısını belgelemek için değil, öğrenmeyi destekleyen geliştirici bir geri bildirim sistemi olarak tasarlanmıştır. Formatif (biçimlendirici) yaklaşımı temel alan bu sistemde geri bildirimin asıl işlevleriyle ilgili olarak aşağıdakilerden hangisi söylenemez?', 'PUBLISHED')
