INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('bd035a8f-33b2-52a8-8086-aab601ca1163', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Sosyal Bilimler Alan Becerileri kapsamında ele alınan ''Tarihsel Empati'' becerisi, tarih öğretiminde bireylerin sadece geçmişi öğrenmesini değil, geçmişi doğru anlamlandırmasını da hedefler. Bu becerinin kazandırıldığı bir öğrenciden aşağıdakilerden hangisini yapması beklenir?', 'PUBLISHED')
