INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('3cd9e81f-c23c-553e-b2fc-33a143ea2ac7', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli''ne göre, öğrencilerin günlük hayatta karşılaştıkları olay ve olguları anlamlandırırken sadece teorik ezber yapmayıp, bilimsel becerileri etkili bir şekilde kullanmalarını, probleme yönelik kararlar alarak hayata yönelik faaliyetlerini bu kararlar bağlamında düzenlemelerini hedefleyen alan becerisi aşağıdakilerden hangisidir?', 'PUBLISHED')
