INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('bbbd62d4-7937-5b62-b023-8e487d71ced1', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Bireyin sadece kendi içinde bulunduğu toplumsal değerleri değil, aynı zamanda farklı coğrafya ve toplulukların kültürel yapılarını da tanıması, çok kültürlü ortamlarda kültürel normlara uygun, ön yargılardan uzak etkileşimsel davranışlar geliştirmesi beklenmektedir. Bu durum, öğretim programlarında yer alan okuryazarlık türlerinden hangisiyle doğrudan ifade edilir?', 'PUBLISHED')
