INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('972942e1-0507-5bf7-93df-2280a13e0428', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Bir öğretmen, sınıfındaki öğrencilerden önce okullarında yaşanan ''enerji israfı'' sorununu tespit etmelerini, ardından matematik ve teknoloji derslerindeki bilgilerini kullanarak bu israfı önleyecek akıllı bir aydınlatma prototipi tasarlamalarını istemiştir. Öğrenciler bu prototipi üretip bir hafta boyunca çalışıp çalışmadığını test etmişlerdir. Öğretmenin uyguladığı bu eğitim süreci aşağıdakilerden hangisinin temel adımlarını yansıtmaktadır?', 'PUBLISHED')
