INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('3793bae0-7731-5ed1-8166-59883c1b86a1', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli''nde kazanımların yerini alan ''öğrenme çıktıları'', salt bilgiden ibaret statik yapılar değildir. Modelin teorik altyapısına göre, bir öğrenme çıktısının oluşabilmesi için temel içerik bilgisinin aşağıdaki unsurlardan hangisiyle organik olarak birleşmesi zorunludur?', 'PUBLISHED')
