INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('04487582-929a-5568-b047-dc462ee5592b', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Tarih dersinde Sanayi İnkılabı''nı işleyen bir öğretmen, öğrencilerden bu dönemin öncesi ve sonrası arasındaki üretim biçimlerini karşılaştırmalarını istemiştir. Öğrenciler, el tezgahlarından fabrikasyon üretime geçişte nelerin köklü bir şekilde başkalaştığını, tarımsal kültürün ise belirli bölgelerde nasıl aynı kalmaya devam ettiğini tartışmışlardır. Bu süreçte öğrencilerin kullandığı ağırlıklı Sosyal Bilimler Alan Becerisi aşağıdakilerden hangisidir?', 'PUBLISHED')
