INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('21a5605d-a8ee-543f-a646-1c20908ba673', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Sosyal-Duygusal Öğrenme (SDÖ) çerçevesinde; benlik becerileri kişinin kendi iç dünyasıyla, sosyal yaşam becerileri ise toplumsal etkileşimiyle ilgilidir. Model, bu iki alanın kesişim noktasında yer alan ve bireyin hem kişisel hem de toplumsal yönünden eş zamanlı beslenen ''Ortak/Birleşik Beceriler'' tanımlamıştır. Aşağıdakilerden hangisi bu beceri grubunda yer alan süreçlerden biridir?', 'PUBLISHED')
