INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('4a1ba557-8555-5a23-bf3a-4fd5b4b809be', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Veri Okuryazarlığı, bilgiyi çağın gereklerine uygun olarak yönetebilmeyi sağlar. Bir projenin araştırma aşamasında, verileri toplayan, bunları tablolaştırarak sınıflandıran, grafiklerle görselleştiren ve ardından bu verilerin istatistiksel değişkenlerini hesaplayarak karmaşık yapıyı basitleştiren bir öğrencinin, aşağıdaki beceri alanlarından hangisine doğrudan başvurduğu söylenemez?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
