INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('d7693067-f849-59dc-927f-c8ac84fa77fb', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Fen bilimleri öğretmeni Ayşe Hanım, üstün potansiyelli öğrencileri için ders planında yer alan ''Hücre'' konusunu işlerken, müfredattaki standart bilgilerin ötesine geçerek güncel genetik araştırmalardan, biyoteknoloji uygulamalarından ve tıp etiği gibi çok disiplinli tartışma konularından materyaller eklemiştir. Ayşe Hanım''ın yaptığı bu uyarlama, farklılaştırmanın hangi boyutu altında bir uygulamadır?', 'PUBLISHED')
