INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('8f4c5261-93c2-51fe-8896-fe80a00a2345', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Bireyin kazancını doğru yönetmesi, gelir ve harcama arasındaki ilişkiyi kurması, kredi veya kredi kartı gibi borçlanma araçlarını risk analizi yaparak kullanması ve geleceğe dönük doğru tasarruf/yatırım stratejilerini uygulayabilmesi aşağıdaki okuryazarlık türlerinden hangisinin kazanımları arasındadır?', 'PUBLISHED')
