INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('df06eec1-ba31-51f5-8013-98b1712d6548', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'İnsanlarla ilişkilerde uyum gösterebilme, risk alarak toplumda ihtiyaç duyulan bir ürün veya hizmete olan boşluğu sezme, bu ürünle ilgili planlama yapma, kaynakları yönetme ve ortaya konulan değeri çevresine ulaştırma (pazarlama) süreçlerini kapsayan Sosyal Bilimler Alan Becerisi aşağıdakilerden hangisidir?', 'PUBLISHED')
