INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('4cc9532f-05aa-5124-9029-268c99b02919', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Modern dünya problemleri, genellikle tek boyutlu çözümlerle aşılamayacak kadar karmaşıktır. Türkiye Yüzyılı Maarif Modeli; öğrencilerin neden-sonuç ilişkilerini analiz etmelerini, yapıyı oluşturan parçaları ve bütünü aynı anda algılamalarını, süreçteki davranışları tahmin eden araçlar oluşturarak sürdürülebilir çözümler üretmelerini hedefleyen geniş çaplı bir okuryazarlık sunar. Tüm bu okuryazarlık türlerini de kapsayacak biçimde problemleri bütüncül kavramayı sağlayan bu okuryazarlık türü aşağıdakilerden hangisidir?', 'PUBLISHED')
