INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('821ce8d2-fee1-5a62-9617-ec238c7f4e36', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Bilgiyi üreten, soyut ve eleştirel düşünen, karşılaştığı problemleri algoritmik bir mantıkla çözebilen, aynı zamanda dijital ortamlarda iletişim becerileriyle topluma etik çerçevede katkı sağlayan bir bireyi tanımlamak için kullanılan alan becerisi aşağıdakilerden hangisidir?', 'PUBLISHED')
