INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('5de1dc08-0a38-5843-9331-878dea6689e1', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Ontolojik bütünlük (ruh ve beden bütünlüğü) kapsamında ele alınan ''Sağlıklı'' öğrenci profilinde, bireyin yalnızca hastalıklardan uzak olması değil, çok boyutlu bir iyi olma hali içinde bulunması hedeflenir. Buna göre, aşağıdakilerden hangisi bu profile uygun bir davranış göstergesi olamaz?', 'PUBLISHED')
