INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('d02e32f7-5f18-5e12-988e-268bc56b7da1', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Doğal kaynakların sonsuz bir depo olmadığını fark eden, tüm canlıların yaşam haklarına saygı duyan, karbon ayak izini azaltmaya yönelik bireysel önlemler alan ve şimdiki kararlarının gelecek nesillerin yaşam alanını tehlikeye atmaması gerektiği bilinciyle hareket eden bir öğrenci, aşağıdaki okuryazarlık alanlarından hangisinde yüksek bir gelişim göstermiştir?', 'PUBLISHED')
