INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('b8c3c978-1ff4-5aff-bc87-86db2162c21d', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Öğretmen Burak Bey, sınıfındaki bazı öğrencilerin gürültülü ortamlarda dikkatini toplayamadığını, bazılarının ise grup etkileşimi ile daha hızlı öğrendiğini fark etmiştir. Bunun üzerine sınıfın bir köşesini paravanlarla çevirerek kulaklıkların bulunduğu ''sessiz okuma alanı'' yapmış; diğer bir köşesini ise hareketli masalarla ''grup tartışma istasyonu'' hâline getirmiştir. Burak Bey''in yaptığı bu düzenleme, farklılaştırılmış öğretimin hangi öğesinde gerçekleştirilen bir uygulamadır?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
