INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('dc780c51-b075-5785-ba55-3321a37d69af', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli, bilginin birbirinden yalıtılmış parçalar hâlinde sunulmasını reddeder. Bu bağlamda, örneğin ''küresel ısınma'' konusunun, eğitim-öğretim yılının aynı haftalarında hem fen bilimlerinde, hem matematikte grafik okuma becerileriyle hem de Türkçede okuma anlama metinleriyle eş güdümlü ve birbirini destekleyecek şekilde işlenmesi, öğretim programlarının tasarımındaki hangi temel ilkeyi yansıtır?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
