INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('1626708f-96de-5b4f-b2c0-5c2b7cc6ea31', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli öğretim programları tasarlanırken; Erdem-Değer-Eylem Çerçevesi, Sosyal-Duygusal Öğrenme (SDÖ) Becerileri ve Okuryazarlık türleri bağımsız birer ders olarak kurgulanmamıştır. Bunun yerine bu yapılar; Matematik, Tarih, Türkçe gibi tüm derslerin kazanımlarına, işleniş süreçlerine ve yaşantılarına organik olarak yedirilmiştir. Modelin bu stratejisini ifade eden temel kavram aşağıdakilerden hangisidir?', 'PUBLISHED')
