INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('782fb066-a40a-5e20-a2a9-f9cae9456625', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Sosyal-Duygusal Öğrenme benlik becerileri kapsamında bireyin kendi iç dünyasını sağlıklı yönetmesi hedeflenir. Öğrencinin daha önce yaşadığı deneyimleri gözden geçirmesi, başarılarından veya hatalarından ders çıkarması ve yeni karşılaştığı durumlarda kendi davranışlarını bu tecrübeler ışığında yeniden uyarlaması sürecine ne ad verilir?', 'PUBLISHED')
