INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('fc0adf47-366c-5cf7-a1e7-f4ce570750f6', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'İnternet üzerinden araştırma ödevi hazırlayan bir lise öğrencisi, ulaştığı metinlerin ve kullandığı görsellerin asıl sahiplerini kaynakçasında eksiksiz olarak belirtmekte, telif hakkı uyarısı olan dijital içerikleri izinsiz olarak çoğaltmamakta ve kendi içeriklerini üretirken başkalarının emeğine saygı göstermektedir. Öğrencinin sergilediği bu davranış, aşağıdaki okuryazarlık alt becerilerinden hangisinin kazanıldığını gösterir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
