INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('473f8743-214f-597c-8cb6-8b0a79793394', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli''nde ''Yetkin ve Erdemli İnsan'' profilinin inşası dört ana bütünlük üzerine kuruludur. Bu alanlardan biri, öğrencinin yalnızca akademik bilgiyi depolamasını değil; doğruyu yanlıştan ayıracak bir ahlaki pusulaya, sanat eserlerini takdir edecek bir güzellik algısına ve değerleri içselleştirip eyleme dönüştürme iradesine sahip olmasını gerektirir. Değer, ahlak ve estetiği merkeze alan bu bütünlük alanı aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
