INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('5e8b4be5-c907-5416-9a57-dd229be4d182', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli öğretim programlarında öğrenme-öğretme yaşantıları tasarlanırken, öğrencilerin yeni bir ünite veya temaya zihinsel olarak hazır başlamaları önem taşır. Bu nedenle, yeni konunun inşası için öğrencinin önceden bilmesi veya sahip olması gerektiği varsayılan önkoşul bilgi ve beceriler programda açıkça belirtilir. Sistemin yapısında yer alan bu ''ön öğrenmeler'', aşağıdaki kavramlardan hangisiyle isimlendirilmiştir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
