INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('dc3aacb5-fa6f-5f89-8123-6f06d8468d9b', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli kapsamında hedeflenen öğrenci niteliklerinden biri de bireyin salt akademik zekâya odaklanmayıp güçlü bir duygusal derinliğe sahip olmasıdır. Bireyin insanlara, doğaya ve yardıma muhtaç olan tüm canlılara karşı derin bir duyarlılık geliştirmesi, onların acılarını dindirmek için içsel bir sorumluluk hissederek destekleyici eylemlerde bulunması, profilin hangi alt kavramıyla ifade edilir?', 'PUBLISHED')
