INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('bfc103d1-7be3-5e4e-80de-8804ec460a60', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Bir tartışma ve araştırma ortamında öğrenciden; farklı kaynaklardan edindiği kanıtları incelemesi, sunulan argümanların güçlü ve zayıf yönlerini tartması, nesnel ölçütler ışığında bu bilgileri sınayarak nihai ve gerekçeli bir karara (yargıya) varması beklenmektedir. Öğrencinin sergilediği bu zihinsel eylem süreci, beceriler çerçevesine göre aşağıdaki kavramlardan hangisine karşılık gelir?', 'PUBLISHED')
