INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('c5e60500-38be-5fa1-a178-b1ce10b1ef75', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Toplumun bir parçası olan bireyin; anayasada güvence altına alınan temel hak ve hürriyetlerini bilmesi, devlete ve topluma karşı sorumluluklarını (vergi verme, yasalara uyma vb.) eksiksiz yerine getirmesi ve demokratik katılım süreçlerine aktif destek vererek toplumsal fayda üretmesi beklenmektedir. Bu niteliklerin tümü, öğretim programlarında yer alan hangi okuryazarlık alanının doğrudan bir sonucudur?', 'PUBLISHED')
