INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('337a8a7a-b24e-5e85-afaa-d765ddc046ca', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Bir proje grubu, haftalarca hazırlandıkları sunumu yapacakları gün okulun elektrik sisteminde arıza çıkması nedeniyle dijital materyallerini kullanamamıştır. Ancak gruptaki bir öğrenci panik yapmak veya sunumu iptal etmek yerine; hemen duruma uyum sağlamış, tahtayı ve elindeki kâğıtları kullanarak planını o anki şartlara göre başarıyla yeniden düzenlemiştir. Bu öğrenci, Sosyal-Duygusal Öğrenme (SDÖ) ''Ortak Becerileri''nden hangisini etkin şekilde kullanmıştır?', 'PUBLISHED')
