INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('633eb92e-1c1e-5d0b-9384-e66f94ec9c40', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Maarif Modeli''nin kapsayıcı ölçme anlayışında, performans görevleri tasarlanırken soruların soyut, izole ve akademik kurmacalardan çok, öğrencilerin okul dışındaki hayatlarında karşılaşabilecekleri gerçek sorunlara (örneğin ev bütçesi planlama, yerel bir çevre sorununa çözüm projesi yazma) dayanması istenir. Değerlendirmenin bu şekilde gerçek hayatın dinamikleriyle ilişkilendirilmesi, pedagojik ölçme literatüründe hangi kavramla açıklanır?', 'PUBLISHED')
