INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('689f35b0-6889-5160-8d8f-adb1b8dc5bb5', '27372eac-908b-54d8-b8f9-77b260c7d060', 'b6120c26-c2a8-5e3d-9366-e61a56885f47', 'SINGLE_CHOICE', 'Sınıf içi farklılaştırma uygulamalarında öğretmen ile öğrenci arasında ortaklaşa alınan kararları içeren anlaşmalar yapılabilir. Bu anlaşmalar; öğrencinin belirli bir zaman diliminde (örneğin iki haftalık bir proje) hangi görevleri, hangi kaynakları kullanarak ve hangi hızda tamamlayacağına dair çerçeveyi belirler. Öğrencinin kendi öğrenme sorumluluğunu üstlenmesini sağlayan ve esneklik sunan bu farklılaştırma aracı aşağıdakilerden hangisidir?', 'PUBLISHED')
