INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('8cba841c-3aea-5a46-8295-d4db007a0c6c', '27372eac-908b-54d8-b8f9-77b260c7d060', 'a181169f-1ac8-5bc3-91a2-f08afdffc81c', 'SINGLE_CHOICE', 'Bir lisede görev yapan psikolojik danışman, öğrencilerin yetenek testleri ve ilgi envanterlerini analiz ederek; fen bilimlerine yatkın olanları ilgili projelere, mesleki eğilimi olanları ise çıraklık veya sanat atölyelerine kanalize etmektedir. Öğrencilerin istidat ve kabiliyetleri doğrultusunda uygun alanlara kaydırılmasını sağlayan bu uygulama, 1739 sayılı Millî Eğitim Temel Kanunu''nun hangi ilkesiyle doğrudan ilişkilidir?', 'PUBLISHED')
