INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('83f850a4-e04c-50cc-a877-d2b481d99fa6', '27372eac-908b-54d8-b8f9-77b260c7d060', 'a181169f-1ac8-5bc3-91a2-f08afdffc81c', 'SINGLE_CHOICE', 'MEB Okul Öncesi Eğitim ve İlköğretim Kurumları Yönetmeliği''ne göre, mecburi öğrenim çağı dışına çıkmış olan ve yönetmeliğin kendisine sağladığı ''iki yıl daha öğrenim görme'' imkânını kullanarak 8. sınıfa geçen bir ortaokul öğrencisinin durumu hakkında aşağıdakilerden hangisi doğrudur?', 'PUBLISHED')
