INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('d81fa8de-2c84-5bf0-b64d-17196fe9bf5f', '27372eac-908b-54d8-b8f9-77b260c7d060', 'a181169f-1ac8-5bc3-91a2-f08afdffc81c', 'SINGLE_CHOICE', '4483 sayılı Memurlar ve Diğer Kamu Görevlilerinin Yargılanması Hakkında Kanun uyarınca yetkili merci tarafından bir iddiayı araştırmak üzere görevlendirilen ön incelemeci, soruşturma kapsamında çeşitli yetkilere sahiptir. Aşağıdakilerden hangisi ön inceleme ile görevlendirilen kişinin yetkileri arasında yer almaz?', 'PUBLISHED')
