INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('e8f4aaca-a7a0-5dd2-b23f-213b9b16ae72', '27372eac-908b-54d8-b8f9-77b260c7d060', 'a181169f-1ac8-5bc3-91a2-f08afdffc81c', 'SINGLE_CHOICE', '5442 sayılı İl İdaresi Kanunu''na göre, ilin genel idaresinden sorumlu olan vali, ildeki devlet dairelerini, müesseselerini ve memurları denetleme yetkisine sahiptir. Kuvvetler ayrılığı ve teşkilat yasaları gereği vali aşağıdaki memur gruplarından hangisini denetleme yetkisine sahip değildir?', 'PUBLISHED')
