INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('2ff71d08-f416-5a3d-9333-d5d6b2b59fe7', '27372eac-908b-54d8-b8f9-77b260c7d060', 'a181169f-1ac8-5bc3-91a2-f08afdffc81c', 'SINGLE_CHOICE', 'MEB Okul Öncesi Eğitim ve İlköğretim Kurumları Yönetmeliği''ne göre, ilköğretim kademelerinde bir ders saati süresi 40 dakikadır. Yönetmelik, hangi eğitim kademelerinde öğretmenler kurulu kararıyla ''blok ders'' yapılmasına izin vermiştir ve blok ders en fazla kaç ders saatini kapsayacak şekilde planlanabilir?', 'PUBLISHED')
