INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('efef8dd6-ba3a-5f74-88e0-18f4193bd685', '27372eac-908b-54d8-b8f9-77b260c7d060', 'a181169f-1ac8-5bc3-91a2-f08afdffc81c', 'SINGLE_CHOICE', 'Millî Eğitim Bakanlığı Ortaöğretim Kurumları Yönetmeliğinde yapılan değişikliklere göre lise kademesinde uygulanan sorumluluk sınavları, bazı spesifik dersler için tek aşamalı yapılamaz. Aşağıdaki derslerden hangilerinin sorumluluk sınavları mutlaka hem yazılı hem de uygulamalı olarak iki aşamada gerçekleştirilmek zorundadır?', 'PUBLISHED')
