INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('489b071d-f1d0-5e0b-90af-64a3222efc36', '27372eac-908b-54d8-b8f9-77b260c7d060', 'a181169f-1ac8-5bc3-91a2-f08afdffc81c', 'SINGLE_CHOICE', 'Mesleki teknik anadolu lisesinde öğrenim gören bir öğrenci, mazeretsiz devamsızlık sınırını aştığı için sınıf tekrarına kalmıştır ancak yasal olarak öğrenim görme hakkı hâlen devam etmektedir. Son yönetmelik düzenlemelerine göre, okul idaresinin bu öğrencinin eğitim hayatını sürdürebilmesi için kendisine sunacağı en güncel yasal seçenek aşağıdakilerden hangisidir?', 'PUBLISHED')
