INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('d3ed2310-cd36-58c7-833e-f2a1ded98aa9', '27372eac-908b-54d8-b8f9-77b260c7d060', 'a181169f-1ac8-5bc3-91a2-f08afdffc81c', 'SINGLE_CHOICE', '3071 sayılı Dilekçe Hakkının Kullanılmasına Dair Kanun uyarınca, kamu makamlarına verilen bazı dilekçeler içerik veya şekil eksiklikleri nedeniyle idare tarafından işleme alınmaz ve incelenmez. Aşağıdakilerden hangisi dilekçenin incelenmeme (reddedilme) sebeplerinden biri değildir?', 'PUBLISHED')
