INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('69c24bbc-97d9-549f-94ab-ba66cd46f87e', '27372eac-908b-54d8-b8f9-77b260c7d060', 'a181169f-1ac8-5bc3-91a2-f08afdffc81c', 'SINGLE_CHOICE', '4688 sayılı Kamu Görevlileri Sendikaları ve Toplu Sözleşme Kanunu''na göre kamu görevlilerinin sendikaya üye olma süreçleriyle ilgili olarak aşağıda verilen bilgilerden hangisi yanlıştır?', 'PUBLISHED')
