INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('3f7012dc-61b6-5ceb-aa7f-f1bc1fb1f018', '27372eac-908b-54d8-b8f9-77b260c7d060', 'a181169f-1ac8-5bc3-91a2-f08afdffc81c', 'SINGLE_CHOICE', 'Ortaokul 8. sınıfta yapılan bir yazılı sınavda gözetmen öğretmen, bir öğrencinin kopya çektiğini tespit etmiş ve durumu okul yönetimine tutanakla bildirmiştir. MEB Okul Öncesi Eğitim ve İlköğretim Kurumları Yönetmeliği''ne göre, bu öğrencinin o ders için akademik puan değerlendirmesi nasıl yapılmalıdır?', 'PUBLISHED')
