INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('cc67f3a4-f12c-5825-a19c-cc6b4d76e1f0', '27372eac-908b-54d8-b8f9-77b260c7d060', 'a181169f-1ac8-5bc3-91a2-f08afdffc81c', 'SINGLE_CHOICE', 'Millî Eğitim Bakanlığı Ortaöğretim Kurumları Yönetmeliği''nde yapılan güncellemeye göre; bir okulun, programın veya alanın akademik başarı, alınan belgeler ve projeler değerlendirilerek ''merkezi sınav puanıyla öğrenci alan okul'' (nitelikli okul) kapsamına alınması için başvurular her yıl hangi ay içerisinde il/ilçe millî eğitim müdürlüklerine yapılır?', 'PUBLISHED')
