INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('f1aa0c6f-7cca-5666-8a86-27e1a999750c', '27372eac-908b-54d8-b8f9-77b260c7d060', 'a181169f-1ac8-5bc3-91a2-f08afdffc81c', 'SINGLE_CHOICE', '7528 sayılı Öğretmenlik Mesleği Kanunu''na göre, öğretmenlikte en az 10 yıl hizmeti bulunan ve Millî Eğitim Akademisi tarafından uzman öğretmenlik için düzenlenen eğitimi başarıyla tamamlayan bir öğretmenin, uzman öğretmenlik unvanını alabilmesine kanunen engel olan ''yegane disiplin cezası'' aşağıdakilerden hangisidir?', 'PUBLISHED')
