INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('a03598c1-97db-5314-8cdf-d6606324d332', '27372eac-908b-54d8-b8f9-77b260c7d060', 'a181169f-1ac8-5bc3-91a2-f08afdffc81c', 'SINGLE_CHOICE', 'Özel Öğretim Kurumları Yönetmeliği''nde yapılan güncel değişikliklere göre; 25-72 ay yaş grubundaki çocuklara yönelik kısmi süreli faaliyet göstermek, sosyal, kültürel, sanatsal ve sportif faaliyetleri odak noktasına almak üzere oluşturulan yeni özel öğretim kurumu türünün adı aşağıdakilerden hangisidir?', 'PUBLISHED')
