INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('d65defb1-9518-5682-8188-167a1f74771d', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '1911 yılında İtalya''nın Trablusgarp''a saldırması üzerine Osmanlı Devleti bölgeye karadan veya denizden düzenli ordu gönderememiştir. Bunun üzerine Mustafa Kemal, Enver Bey ve Nuri Bey gibi gönüllü subaylar kılık değiştirerek bölgeye sızmış ve yerel halkı (Senusileri) İtalyanlara karşı başarıyla örgütlemişlerdir. Bu durum, eğitim yönetimindeki liderlik yaklaşımları bağlamında değerlendirildiğinde Mustafa Kemal''in hangi özelliğini en güçlü şekilde vurgular?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
