INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('97339118-a0d5-5cc9-9a9f-5275b2812c38', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Trablusgarp Savaşı''nın ardından 1912 yılında imzalanan Uşi Antlaşması ile Osmanlı Devleti, Kuzey Afrika''daki son toprak parçasını İtalya''ya bırakmıştır. Aynı antlaşmada On İki Ada''nın Balkan Savaşları bitene kadar ''geçici olarak'' İtalya''da kalması kararlaştırılmış, ancak bu adalar bir daha geri alınamamıştır. On İki Ada''nın geçici olarak İtalya''ya bırakılmasının temel nedeni aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-001 Soru Paketi.json (source id ITA-000003)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('ea00a8bf-af9f-5a7a-aa5a-bd6dffb27b75', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'I. Balkan Savaşı''ndaki ağır yenilginin faturasını mevcut hükûmete kesen İttihat ve Terakki Cemiyeti, 1913 yılında gerçekleştirdiği ''Bâb-ı Âli Baskını'' ile Kamil Paşa hükûmetini istifaya zorlamış ve yönetimi tamamen ele geçirmiştir. Bâb-ı Âli Baskını''nın Türk siyasi tarihindeki niteliği hakkında aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-001 Soru Paketi.json (source id ITA-000004)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('a5de4ca6-84ff-5b5c-9da9-fc8fc6d436c8', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Osmanlı Devleti''nin I. Dünya Savaşı''na Almanya''nın yanında İttifak Devletleri safında girmesinde birçok siyasi ve ekonomik etken rol oynamıştır. Aşağıdakilerden hangisi Osmanlı Devleti''nin I. Dünya Savaşı''na girme nedenleri arasında gösterilemez?', 'PUBLISHED')
