-- source: D:\EKYS\content\questions\draft\ITA-001 Soru Paketi.json (source id ITA-000005)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('34d97451-1f1b-5640-83e9-1901287da89f', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Enver Paşa komutasındaki Osmanlı ordusu, I. Dünya Savaşı''nda Kafkas Cephesi''nde Ruslara karşı Sarıkamış Harekâtı''nı başlatmıştır. Turancılık (Pantürkizm) vizyonuyla ve Bakü petrollerine ulaşmak amacıyla başlatılan bu taarruz, kış şartlarının ağırlığı, askerlerin kışlık donanım eksikliği ve lojistik (ikmal) yollarının yetersizliği nedeniyle on binlerce askerin donarak şehit olmasıyla sonuçlanmıştır. Bir yöneticinin stratejik planlama becerisi (sistem okuryazarlığı) göz önüne alındığında, Sarıkamış Harekâtı''ndaki temel yönetsel başarısızlık aşağıdakilerden hangisidir?', 'PUBLISHED')
