-- source: D:\EKYS\content\questions\draft\ITA-001 Soru Paketi.json (source id ITA-000006)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('ac30596f-72f1-52b1-b031-4f47c40da4b4', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Osmanlı Devleti, I. Dünya Savaşı devam ederken 1915 yılında ''Sevk ve İskân Kanunu''nu (Tehcir Kanunu) çıkarmak zorunda kalmıştır. Bu olağanüstü idari kararın alınmasındaki temel askerî ve stratejik gerekçe aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-001 Soru Paketi.json (source id ITA-000007)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('07508997-a508-5c9c-8576-3e181c04a7ec', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'I. Dünya Savaşı''nda Osmanlı Devleti''nin zaferle kapattığı Çanakkale Cephesi, sadece bir askerî savunma başarısı değil, aynı zamanda küresel dengeleri değiştiren büyük bir stratejik kırılmadır. Aşağıdakilerden hangisi Çanakkale Savaşları''nın kazanılmasının yarattığı doğrudan siyasi sonuçlardan biridir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-001 Soru Paketi.json (source id ITA-000008)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('0c0d4da5-3335-52eb-9e0a-1baa79c8b519', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '30 Ekim 1918''de imzalanan Mondros Ateşkes Antlaşması''nın 7. Maddesi ''İtilaf Devletleri güvenliklerini tehdit eden herhangi bir stratejik noktayı işgal edebilecektir'', 24. Maddesi ise ''Vilayet-i Sitte''de (Doğu Anadolu''daki 6 il) bir karışıklık çıkarsa buralar işgal edilecektir'' hükmünü içermektedir. İtilaf Devletleri''nin bu iki maddeyi antlaşma metnine koydurmaktaki asıl amacı aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-001 Soru Paketi.json (source id ITA-000009)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('850cf680-297c-569f-b75b-cd44063fbf16', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'I. Dünya Savaşı sırasında yapılan gizli antlaşmalara göre Batı Anadolu (İzmir ve çevresi) İtalya''ya bırakılmıştı. Ancak 1919''da toplanan Paris Barış Konferansı''nda İngiltere''nin baskısıyla bu bölge İtalya''dan alınarak Yunanistan''a verilmiştir. İngiltere''nin bu diplomatik manevrasının temel jeopolitik nedeni aşağıdakilerden hangisidir?', 'PUBLISHED')
