-- source: D:\EKYS\content\questions\draft\ITA-001 Soru Paketi.json (source id ITA-000010)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('2699b657-6359-5b43-9312-0f96174444a8', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Mondros Ateşkes Antlaşması''nın ardından başlayan işgaller karşısında Anadolu''nun çeşitli yerlerinde Müdafaa-i Hukuk (Millî) Cemiyetleri kurulmuştur. Bu yararlı cemiyetlerin genel özellikleriyle ilgili aşağıdakilerden hangisi yanlıştır?', 'PUBLISHED')
