INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('7fb4bc6f-ba16-535f-b2fc-e0773747e644', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Mustafa Kemal Paşa, 19 Mayıs 1919''da Samsun''a çıkarken İstanbul Hükûmeti tarafından kendisine geniş askeri ve mülki yetkiler tanıyan ''9. Ordu Müfettişi'' unvanı verilmiştir. Hükûmetin Mustafa Kemal''i bu geniş yetkilerle donatarak bölgeye göndermesindeki asıl resmî amacı aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-001 Soru Paketi.json (source id ITA-000012)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('41bb5369-ea74-5f74-804f-94ec88e22f46', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Mustafa Kemal Paşa, 28 Mayıs 1919''da yayımladığı Havza Genelgesi''nde halktan işgalleri protesto eden mitingler düzenlemelerini ve İtilaf Devletleri temsilciliklerine telgraflar çekmelerini istemiştir. Ancak genelgeye ''Bu mitingler sırasında Hristiyan azınlıklara kesinlikle zarar verilmemesi, taşkınlık yapılmaması'' şeklinde kesin bir emir eklemiştir. Mustafa Kemal''in bu uyarıyla gerçekleştirmek istediği stratejik risk yönetimi hedefi aşağıdakilerden hangisidir?', 'PUBLISHED')
