INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('d1feb240-fb72-5aa9-a365-82e5963bc509', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '22 Haziran 1919''da yayımlanan Amasya Genelgesi, Millî Mücadele''nin gerekçesini, amacını ve yöntemini belirleyen bir ihtilal beyannamesi niteliğindedir. Genelgede yer alan hangi madde, Türk tarihinde ilk kez üstü örtülü de olsa ''Millî Egemenlik'' (milletin yönetime katılması / rejim değişikliği) kavramına dayalı yeni bir devlet sisteminin işaretini vermektedir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-001 Soru Paketi.json (source id ITA-000014)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('5359a478-50af-5415-9abb-fc6ea811f457', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Mustafa Kemal Paşa, kendi hazırladığı Amasya Genelgesi''ni tek başına yayımlamak yerine Rauf Orbay, Refet Bele ve Ali Fuat Cebesoy gibi komutanlara imzalatmış; ayrıca Erzurum''daki Kâzım Karabekir ve Konya''daki Cemal Paşaların da telgrafla onayını almıştır. Yönetim bilimlerindeki ''liderlik ve karar alma'' süreçleri açısından bakıldığında, Mustafa Kemal''in bu hamlesindeki asıl amaç aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-001 Soru Paketi.json (source id ITA-000015)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('6c158663-21ca-5396-aefd-d5549b006691', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Erzurum Kongresi (23 Temmuz - 7 Ağustos 1919), Doğu Anadolu Müdafaa-i Hukuk Cemiyeti ile Trabzon Muhafaza-i Hukuk Cemiyeti''nin gayretleriyle, bölgedeki Ermeni ve Rum tehlikesine karşı toplanmıştır. Ancak kongre sonunda alınan kararlar sadece Doğu''yu değil, tüm ülkeyi ilgilendirmiştir. Bu durum tarih literatüründe Erzurum Kongresi''nin hangi özelliğiyle ifade edilir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-001 Soru Paketi.json (source id ITA-000016)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('824226e3-c8bc-5f16-9326-f1074534cb5b', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '4 Eylül 1919''da toplanan Sivas Kongresi''nde, Anadolu ve Trakya''nın farklı bölgelerinde işgallere karşı birbirinden bağımsız mücadele eden tüm Müdafaa-i Hukuk Cemiyetleri, ''Anadolu ve Rumeli Müdafaa-i Hukuk Cemiyeti'' (ARMHC) adı altında tek bir çatı altında birleştirilmiştir. Örgütsel yönetim (sistem okuryazarlığı) açısından bu kararın temel amacı aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-001 Soru Paketi.json (source id ITA-000017)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('dc6ae692-2100-591e-9932-ac4a23179c85', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Sivas Kongresi çalışmalarını sürdürürken, Temsil Heyeti idari bir karar alarak Ali Fuat (Cebesoy) Paşa''yı Batı Anadolu Kuvay-ı Milliye Umum Komutanlığına atamıştır. İdare hukuku ve siyaset bilimi prensipleri bağlamında, bir kurulla alınan bu ''atama'' kararı, Temsil Heyeti''nin aşağıdaki yetkilerden hangisini kullandığının (bir hükûmet gibi hareket ettiğinin) kesin kanıtıdır?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-001 Soru Paketi.json (source id ITA-000018)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('e13261b8-df82-56a4-92b8-5e9656203f9b', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Sivas Kongresi''nden sonra Anadolu''da ipleri elinden kaçıran Damat Ferit Paşa Hükûmeti istifa etmek zorunda kalmış, yerine kurulan Ali Rıza Paşa Hükûmeti ise Bahriye Nazırı Salih Paşa''yı Temsil Heyeti (Mustafa Kemal) ile görüşmesi için Amasya''ya göndermiştir. Tarihe ''Amasya Görüşmeleri (Protokolleri)'' olarak geçen bu temasın Millî Mücadele açısından en büyük diplomatik sonucu aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-001 Soru Paketi.json (source id ITA-000019)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('065657ec-142a-5dfc-b02f-76cd535495d7', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '23 Nisan 1920''de Ankara''da açılan I. Türkiye Büyük Millet Meclisi (TBMM), olağanüstü şartlar altında kurulmuş ihtilalci bir meclistir. Meclis, dönemin kriz şartlarında hızlı kararlar alıp bu kararları derhal uygulayabilmek amacıyla kuvvetler ayrılığı prensibini reddetmiş; yasama ve yürütme (daha sonra yargı) yetkilerini kendi bünyesinde toplamıştır. I. TBMM''nin uyguladığı bu devlet yönetim sistemine ne ad verilir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-001 Soru Paketi.json (source id ITA-000020)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('cc66bdf6-e620-53a9-8691-4029b8ce5d96', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'I. TBMM açıldıktan sonra Anadolu''nun dört bir yanında (Anzavur, Kuva-yi İnzibatiye, Yozgat, Konya vb.) meclisin otoritesini sarsmaya yönelik ayaklanmalar çıkmıştır. Bir yöneticinin krizi kurumsal ve yasal araçlarla bastırma becerisine benzer şekilde, TBMM de bu isyanları bastırmak için çeşitli yasal, adli ve iletişimsel önlemler almıştır. Aşağıdakilerden hangisi I. TBMM''nin bu ayaklanmalara karşı otoritesini sağlamak için aldığı önlemlerden biri değildir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
