INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('492ed470-2cb9-58bd-9326-9ced7da0b902', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Kurtuluş Savaşı''nda TBMM''nin askerî ve siyasi alanda kazandığı ilk uluslararası başarı Gümrü Antlaşması''dır. Kâzım Karabekir Paşa''nın Doğu Cephesi''ndeki zaferinin ardından Ermenistan ile imzalanan bu antlaşmanın Millî Mücadele açısından en önemli siyasi sonucu aşağıdakilerden hangisidir?', 'PUBLISHED')
