-- source: D:\EKYS\content\questions\draft\ITA-002 Soru Paketi.json (source id ITA-000022)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('1343dcae-1007-580b-bea9-c81ce88ba608', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Sivas Kongresi''nde Temsil Heyeti tarafından Batı Anadolu Kuvay-ı Milliye Umum Komutanlığına atanan Ali Fuat Paşa''nın, Yunan kuvvetlerine karşı düzenlediği Gediz Taarruzu''nda (Ekim 1920) başarısız olması, Millî Mücadele stratejisinde nasıl bir idari değişimi zorunlu kılmıştır?', 'PUBLISHED')
