INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('f7127bf7-f721-5b05-8333-66dc5b44a07e', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'I. İnönü Savaşı''nın kazanılması, TBMM''nin kurduğu düzenli ordunun ilk başarısı olması sebebiyle hem içeride hem de dışarıda TBMM''nin otoritesini büyük ölçüde artırmıştır. Aşağıdakilerden hangisi I. İnönü Zaferi''nin ortaya çıkardığı dış politika (diplomatik) sonuçlarından biri değildir?', 'PUBLISHED')
