INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('26d83a15-1097-56e1-9241-748fddbf2eb0', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'İtilaf Devletleri, I. İnönü Savaşı''nın ardından düzenlenen Londra Konferansı''na, Türk milletini temsil etmek üzere hem İstanbul Hükûmeti''ni hem de TBMM Hükûmeti''ni birlikte davet etmişlerdir. TBMM heyeti bu oyunu önceden sezerek konferansa sadece ''doğrudan çağrılması'' hâlinde katılacağını bildirmiştir. İtilaf Devletleri''nin bu diplomatik davet stratejisindeki asıl amacı aşağıdakilerden hangisidir?', 'PUBLISHED')
