INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('1b36a035-29e6-5275-947e-9aef60e0e95d', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'I. İnönü Savaşı sonrasında TBMM tarafından kabul edilen 1921 Anayasası (Teşkilat-ı Esasiye Kanunu), Türkiye Devleti''nin ilk anayasasıdır. Bu anayasanın ihtilalci niteliğini gösteren ve eski rejimi (saltanat sistemini) hukuken ve felsefi olarak yıktığını kanıtlayan en temel madde aşağıdakilerden hangisidir?', 'PUBLISHED')
