INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('5f6aa673-be43-5b90-9f3f-4bcd47886b09', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Bir ülkenin eğitim sistemini yöneten kadroların, o ülkenin bağımsızlık sembollerinin felsefesine hâkim olması beklenir. 12 Mart 1921''de İstiklal Marşı''nın TBMM tarafından resmen kabul edilmesi, dönemin olağanüstü savaş şartları göz önüne alındığında öncelikle hangi stratejik ve sosyo-psikolojik amaca hizmet etmiştir?', 'PUBLISHED')
