INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('43a4c2d9-bd92-57b6-982b-c78a3cc929c1', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'I. İnönü Savaşı sonrasında TBMM ile Sovyet Rusya arasında imzalanan Moskova Antlaşması''nın maddelerinden biri ''İki taraftan birinin tanımadığı uluslararası bir antlaşmayı, diğeri de tanımayacaktır.'' şeklindedir. Bu maddenin diplomasi tarihindeki anlamı ve TBMM açısından sonucu aşağıdakilerden hangisidir?', 'PUBLISHED')
