INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('bda42ae1-7da6-5162-8905-066dec98d0aa', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'II. İnönü Savaşı''nın kazanılmasının ardından TBMM Başkanı Mustafa Kemal Paşa, Batı Cephesi Komutanı İsmet Paşa''ya gönderdiği tarihî telgrafta ''Siz orada yalnız düşmanı değil, milletin makûs (kötü giden) talihini de yendiniz.'' ifadelerini kullanmıştır. Mustafa Kemal''in bu sözüyle asıl kastettiği tarihsel durum aşağıdakilerden hangisidir?', 'PUBLISHED')
