INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('31398440-b09b-59d5-8836-ebc5f7c340f6', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Kütahya-Eskişehir Muharebelerinde Türk ordusunun Yunan kuvvetleri karşısında kayıplar vermesi üzerine Mustafa Kemal Paşa, orduya Sakarya Nehri''nin doğusuna çekilme emri vermiştir. Bir kriz anında alınan bu radikal ''geri çekilme (ricat)'' kararının temel askerî ve stratejik gerekçesi aşağıdakilerden hangisidir?', 'PUBLISHED')
