INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('0a89bfaa-65d7-5b1b-b15a-16ed320862fd', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Kütahya-Eskişehir Muharebelerinin en şiddetli günlerinde, top seslerinin Ankara''dan duyulduğu bir kriz ortamında Mustafa Kemal Paşa, 16 Temmuz 1921''de Ankara''da I. Maarif (Eğitim) Kongresi''ni toplamıştır. Bekaa sorununun zirvede olduğu bir dönemde eğitim kongresinin toplanması, Atatürk''ün vizyonuyla ilgili neyin göstergesidir?', 'PUBLISHED')
