INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('809bb1ff-a85f-5e5f-bc97-c77820405390', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Kütahya-Eskişehir Savaşlarındaki geri çekilmenin ardından Meclis''te oluşan kriz ortamında, TBMM 5 Ağustos 1921''de ''Başkomutanlık Kanunu''nu çıkararak kendi sahip olduğu yasama ve yürütme yetkilerini üç ay süreyle Mustafa Kemal Paşa''ya devretmiştir. Demokrasinin özü olan yetkilerin tek bir kişiye devredilmesinin yönetim bilimi (kriz yönetimi) açısından temel gerekçesi aşağıdakilerden hangisidir?', 'PUBLISHED')
