INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('5e779b6c-e2bd-5375-a9fb-5735bc6a0d35', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Mustafa Kemal Paşa, Başkomutanlık yetkisini aldıktan sonra 7-8 Ağustos 1921 tarihlerinde ''Tekâlif-i Milliye (Millî Yükümlülükler) Emirleri''ni yayımlamıştır. Halka elindeki silah, cephane, yiyecek, giyecek ve taşıtların belirli bir kısmını bedeli sonradan ödenmek üzere devlete teslim etme zorunluluğu getiren bu emirlerin askeri stratejideki anlamı aşağıdakilerden hangisidir?', 'PUBLISHED')
