-- source: D:\EKYS\content\questions\draft\ITA-002 Soru Paketi.json (source id ITA-000033)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('7a965810-c41a-5eb7-9ace-3fff8ae001c7', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Sakarya Meydan Muharebesi''nin en kritik anında Başkomutan Mustafa Kemal Paşa, ''Hattı müdafaa yoktur, sathı müdafaa vardır. O satıh bütün vatandır.'' emrini vererek dünya harp tarihine yeni bir taktik kazandırmıştır. Bu stratejik emrin askerî ve taktiksel anlamı aşağıdakilerden hangisidir?', 'PUBLISHED')
