-- source: D:\EKYS\content\questions\draft\ITA-002 Soru Paketi.json (source id ITA-000034)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('68e3b525-ac59-553c-b840-412702bc5e3a', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Sakarya Meydan Muharebesi''nin Türk ordusunun kesin zaferiyle sonuçlanması, İtilaf Devletleri bloğunda büyük bir çözülmeye neden olmuştur. Bu zaferin ardından imzalanan ve Fransa''nın işgal ettiği bölgelerden çekilmesiyle ''Güney Cephesi''nin kapanmasını'' sağlayan diplomatik antlaşma aşağıdakilerden hangisidir?', 'PUBLISHED')
