INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('8be0be12-ebbc-54b1-bab0-9830a0fb3d6f', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Sakarya Zaferi''nden sonra Türk ordusu düşmanı Anadolu''dan tamamen atmak için hemen taarruza geçmemiş; yaklaşık bir yıl boyunca beklemiş ve yoğun bir hazırlık dönemi geçirmiştir. Ordunun bir yıl boyunca taarruzu ertelemesinin (beklemesinin) temel stratejik gerekçesi aşağıdakilerden hangisidir?', 'PUBLISHED')
