-- source: D:\EKYS\content\questions\draft\ITA-002 Soru Paketi.json (source id ITA-000036)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('112426f7-4199-52a8-b6e2-851d34c225c6', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Büyük Taarruz''un zaferle sonuçlanması üzerine 11 Ekim 1922''de Mudanya Ateşkes Antlaşması imzalanmıştır. Bu antlaşmada yer alan ''İstanbul, Boğazlar ve çevresinin yönetimi TBMM Hükûmeti''ne bırakılacaktır'' maddesi, diplomatik ve idari hukuk açısından hangi anlama gelmektedir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-002 Soru Paketi.json (source id ITA-000037)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('770c14eb-5bf1-5a9a-b624-f9954e4479fd', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'İtilaf Devletleri, Mudanya Ateşkesi''nden sonra yapılacak olan barış konferansına, TBMM Hükûmeti''nin yanı sıra İstanbul Hükûmeti''ni de davet ederek Türk tarafında ikilik çıkarmayı ve masada zayıf bir Türkiye profili oluşturmayı hedeflemiştir. TBMM, bu diplomatik manevrayı boşa çıkarmak ve millî egemenliği tam anlamıyla tesis etmek için 1 Kasım 1922''de hangi radikal siyasi kararı almıştır?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-002 Soru Paketi.json (source id ITA-000038)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('ebe16025-f322-52c5-bfd4-b3df8b80ddac', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Lozan Barış Konferansı''na gönderilecek olan Türk heyetine (İsmet Paşa başkanlığında), TBMM tarafından asla taviz verilmemesi, gerekirse masadan kalkılması emredilen iki temel konu bulunmaktadır. Türkiye''nin tam bağımsızlık ilkesini zedeleyeceği için kesinlikle taviz verilmemesi istenen bu iki konu aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-002 Soru Paketi.json (source id ITA-000039)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('36040fc0-eb6d-5be2-8088-632ba66b4dd0', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Lozan Barış Antlaşması''nda Türkiye''nin lehine veya aleyhine birçok konu karara bağlanmış, ancak bir konu üzerinde uzlaşma sağlanamadığı için ''Türkiye ile İngiltere arasında daha sonra yapılacak ikili görüşmelere bırakılmıştır.'' Lozan''da çözülemeyen tek mesele olan bu konu aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-002 Soru Paketi.json (source id ITA-000040)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('27b42f00-4c26-5e86-835e-31786752ca43', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Lozan Barış Antlaşması''na göre; Boğazların yönetimi, başkanı Türk olan uluslararası bir komisyona bırakılmış ve Boğazların her iki yakası askerden arındırılmıştır. Türkiye''nin tam bağımsızlık ve egemenlik haklarını kısıtlayan bu durum, 1936 yılında imzalanan hangi antlaşma/sözleşme ile Türkiye''nin lehine kesin olarak çözülmüştür?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-003 Soru Paketi.json (source id ITA-000041)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('8448e014-cfed-5b0b-b0d1-b7f924949c48', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '29 Ekim 1923''te Cumhuriyetin ilan edilmesini hızlandıran en önemli siyasi kriz, Ali Fethi (Okyar) Bey hükûmetinin istifası sonrası yeni hükûmetin kurulamamasıyla ortaya çıkan ''Güz Krizi'' (Hükûmet Bunalımı) olmuştur. Cumhuriyetin ilanıyla bu yönetim krizinin aşılmasını sağlayan temel idari değişiklik aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-003 Soru Paketi.json (source id ITA-000042)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('33f130e9-d40e-5d35-8f9c-271c844f3321', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '3 Mart 1924''te Halifelik makamının kaldırılması, Türkiye Cumhuriyeti''nin laikleşme sürecindeki en büyük adımlardan biridir. Aşağıdakilerden hangisi Halifeliğin kaldırılmasının doğrudan ortaya çıkardığı siyasi sonuçlardan biri **değildir**?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-003 Soru Paketi.json (source id ITA-000043)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('66c50a6f-c94b-5fcf-8572-52cb5523f9a0', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Cumhuriyet döneminin ilk muhalefet partisi olan Terakkiperver Cumhuriyet Fırkası (TCF), ekonomide liberalizmi benimsemiş ve parti tüzüğüne ''Partimiz dinî inançlara ve fikirlere saygılıdır.'' maddesini koymuştur. Bu maddenin eski rejim yanlılarını cesaretlendirdiği gerekçesiyle partinin kısa sürede kapatılmasına zemin hazırlayan, genç Cumhuriyet rejimini tehdit eden büyük isyan aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-003 Soru Paketi.json (source id ITA-000044)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('fd09752b-48a1-5476-8129-914dd6bb44ac', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '1926 yılında İsviçre Medeni Kanunu örnek alınarak hazırlanan ''Türk Medeni Kanunu'' ile aile hukukunda, kadın-erkek ilişkilerinde ve mülkiyet haklarında devrim niteliğinde değişiklikler yapılmış, Mecelle yürürlükten kaldırılmıştır. Aşağıdaki haklardan hangisi 1926 tarihli Türk Medeni Kanunu ile kadınlara sağlanan yasal kazanımlar arasında yer **almaz**?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-003 Soru Paketi.json (source id ITA-000045)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('e67a5258-a4d6-5741-be26-2a121ed7057b', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '3 Mart 1924 tarihinde kabul edilen Tevhid-i Tedrisat (Öğretim Birliği) Kanunu ile Türkiye sınırları içindeki yerli, azınlık ve yabancı tüm eğitim kurumları Millî Eğitim Bakanlığına (Maarif Vekâleti) bağlanmıştır. Eğitim yöneticiliği vizyonu açısından değerlendirildiğinde, bu kanunun çıkarılmasındaki temel pedagojik ve sosyolojik amaç aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-003 Soru Paketi.json (source id ITA-000046)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('2765a44c-8542-5d17-ab59-6218ad012e65', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '1 Kasım 1928''de Yeni Türk Harflerinin kabul edilmesinin ardından, bu yeni alfabeyi yetişkinlere ve tüm halka hızlı bir şekilde öğretmek, ülke genelindeki okuma-yazma oranını artırmak amacıyla kurulan ve Mustafa Kemal Atatürk''ün ''Başöğretmen'' unvanıyla bizzat katılım sağladığı yaygın eğitim kurumu aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-003 Soru Paketi.json (source id ITA-000047)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('d8ae584e-3333-5309-a12f-204ea1dff3c2', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '1925 yılında çıkarılan bir kanunla tekke, zaviye ve türbeler kapatılmış; şeyh, derviş, mürit, dede, seyit, çelebi gibi unvanların kullanılması yasaklanmıştır. Atatürk''ün, ''Türkiye Cumhuriyeti şeyhler, dervişler, müritler ve meczuplar memleketi olamaz. En doğru, en hakiki tarikat, medeniyet tarikatıdır.'' sözüyle desteklediği bu toplumsal inkılap, öncelikle Atatürk''ün hangi temel ilkesiyle doğrudan ilişkilidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-003 Soru Paketi.json (source id ITA-000048)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('75568bd6-aca6-5564-9454-d93cf308a174', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '1934 yılında kabul edilen Soyadı Kanunu ile her Türk vatandaşının öz adının yanına Türkçe bir soyadı alması zorunlu kılınmış; aynı kanunla ''ağa, hacı, hafız, hoca, molla, efendi, bey, paşa, hanım'' gibi geleneksel unvan ve lakapların resmî kullanımı yasaklanmıştır. Bu hukuki düzenlemenin toplumsal (sosyolojik) hedefi aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
