INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('0f53f826-252c-5a8d-b6a6-91694b1a32b1', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Kurtuluş Savaşı''nın askerî safhası zaferle sonuçlandıktan sonra, siyasi bağımsızlığın ancak ekonomik bağımsızlıkla kalıcı olabileceği fikrinden hareketle, yeni devletin ekonomi politikalarını belirlemek amacıyla 17 Şubat - 4 Mart 1923 tarihleri arasında ''Misak-ı İktisadi'' (Ekonomi Andı) kararlarının alındığı tarihi kongre hangi şehirde toplanmıştır?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
