INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('8ef389eb-27e2-58bd-94f8-718b533f9978', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '1925 yılında, o dönemde Cumhuriyet''in toplam bütçe gelirlerinin yaklaşık yüzde kırkını oluşturmasına rağmen (devlet büyük bir gelirden vazgeçerek), köylünün üzerindeki ağır ekonomik baskıyı hafifletmek ve tarımsal üretimi teşvik etmek amacıyla kaldırılan Osmanlı''dan kalma geleneksel vergi türü aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
