INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('0812e6b9-b21d-5ce1-9e2b-170e23d92610', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Türkiye Cumhuriyeti ilk yıllarında liberal (serbest piyasa) ekonomi modelini benimsemiş ve Teşvik-i Sanayi Kanunu ile özel müteşebbisleri yatırım yapmaya teşvik etmiştir. Ancak özel sermayenin yetersizliği, teknik bilgi eksikliği ve 1929 Dünya Ekonomik Buhranı''nın yarattığı küresel kriz nedeniyle 1930''ların başından itibaren zorunlu olarak hangi ekonomik modele (ve Atatürk ilkesine) geçiş yapılmıştır?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-003 Soru Paketi.json (source id ITA-000052)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('f47210e5-9711-5660-aea1-edde64d4eb25', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Atatürk''ün ''Egemenlik kayıtsız şartsız milletindir.'' sözü, devletin yönetim şeklinin tek bir aileye veya zümreye değil, doğrudan halkın iradesine dayanması gerektiğini vurgular. Bu bağlamda; saltanatın kaldırılması, TBMM''nin açılması, kadınlara seçme ve seçilme hakkının verilmesi ve çok partili siyasi hayata geçiş denemeleri, Atatürk''ün hangi ilkesinin doğrudan birer yansımasıdır?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-003 Soru Paketi.json (source id ITA-000053)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('fd172833-40d5-5b7b-8d41-cd182cc2d59a', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Atatürk milliyetçiliği kafatası, ırk, din veya mezhep birliğine değil; ortak tarih bilincine, birlikte yaşama arzusuna (kaderde kıvançta birlik) ve dil birliğine dayanan kapsayıcı bir anlayıştır. Buna göre aşağıdakilerden hangisi Atatürk milliyetçiliği ilkesi doğrultusunda atılmış veya savunulmuş bir adım olarak **gösterilemez**?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-003 Soru Paketi.json (source id ITA-000054)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('4d531be7-5e50-5109-b397-95fa80cc189d', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Lozan Barış Antlaşması''nın uygulanması aşamasında ortaya çıkan en zorlu krizlerden biri olan; İstanbul''daki Rumlar ile Batı Trakya''daki Türklerin ''yerleşik (etabli)'' sayılıp diğerlerinin zorunlu göçle karşılıklı yer değiştirmesini öngören, nihayetinde 1930 yılında ''Ahali Mübadelesi Antlaşması'' ile çözüme kavuşturulan uluslararası sorun, Türkiye ile hangi devlet arasında yaşanmıştır?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-003 Soru Paketi.json (source id ITA-000055)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('f6c1a83d-9490-53f6-a6ae-03bf9df00314', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Türkiye Cumhuriyeti, dünya barışını korumak amacıyla Birinci Dünya Savaşı sonrasında kurulan Milletler Cemiyeti''ne (Cemiyet-i Akvam) kuruluşu sırasında üye olmamış; Musul sorunu gibi konularda cemiyetin taraflı tutumu nedeniyle uzun süre teşkilata mesafeli kalmıştır. Ancak Türkiye''nin izlediği ''Yurtta sulh, cihanda sulh'' politikası sayesinde 1932 yılında hangi iki ülkenin ortak daveti üzerine bu teşkilata katılması gerçekleşmiştir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-003 Soru Paketi.json (source id ITA-000056)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('bc48fec3-c4ab-5fc9-b413-06a317ad8bc9', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '1930''lu yıllarda Nazi Almanyası''nın ve özellikle Faşist İtalya''nın Akdeniz ile Balkanlar üzerinde saldırgan, yayılmacı politikalar izlemesi sınır güvenliklerini tehdit etmiştir. Türkiye''nin batı sınırını güvence altına almak amacıyla 1934 yılında Yunanistan, Yugoslavya ve Romanya ile birlikte Atina''da imzaladığı bölgesel güvenlik paktı aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
