INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('a2d4ed31-12da-5a5a-b281-34431373cdad', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Lozan Antlaşması''na göre Boğazların yönetimi başkanı Türk olan uluslararası bir komisyona bırakılmış ve Boğazların her iki yakası (askerden arındırılarak) silahsızlandırılmıştı. Tam bağımsızlığı zedeleyen bu durum, yaklaşan II. Dünya Savaşı tehdidi gerekçe gösterilerek Türkiye''nin diplomatik girişimiyle 1936''da Montrö Boğazlar Sözleşmesi ile değiştirilmiştir. Bu sözleşmenin Türkiye Cumhuriyeti açısından en hayati kazanımı aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-003 Soru Paketi.json (source id ITA-000058)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('47f9cef6-a2ac-57fd-929e-3451ff832f9c', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Türkiye, 1937 yılında doğu ve güneydoğu sınırlarını güvence altına almak, İtalya''nın ''Mare Nostrum'' (Bizim Deniz) diyerek Orta Doğu''da başlattığı yayılmacı saldırgan politikalarına karşı Asya''da caydırıcı bir blok oluşturmak amacıyla İran, Irak ve Afganistan ile bölgesel bir saldırmazlık paktı imzalamıştır. Bu diplomatik paktın adı aşağıdakilerden hangisidir?', 'PUBLISHED')
