INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('37da948d-1c8b-5d0c-bbda-fd476b57b57f', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '1921 Ankara Antlaşması ile Fransa mandasındaki Suriye''ye bırakılan, ancak II. Dünya Savaşı öncesinde Fransa''nın Suriye''den askerlerini çekme kararı almasıyla statüsü Türkiye tarafından uluslararası arenaya taşınan bölgedir. Milletler Cemiyeti''nin hazırladığı ''Sandler Raporu'' doğrultusunda önce bağımsız bir cumhuriyete dönüşen ve sonrasında 1939 yılında kendi meclisinin kararıyla Türkiye anavatanına katılan stratejik yer neresidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-003 Soru Paketi.json (source id ITA-000060)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('edf6f736-0643-5ab0-be5e-6de9066c3d84', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Bir eğitim kurumu yöneticisi, okuldaki öğrenciler arasında sosyal sınıf, maddi gelir düzeyi, ailenin statüsü veya bölgesel köken farklılıklarına dayalı ayrımlar yapılmasını ve bunlara yönelik özel uygulamalar geliştirilmesini kesinlikle yasaklamıştır. Okul forması standardından, yemekhane kullanımına ve okuldaki seçme-seçilme süreçlerine kadar tüm öğrencilere mutlak fırsat eşitliği sunmuştur. Yöneticinin eğitim ortamında sergilediği bu adil, ayrıcalıksız ve bütünleştirici tutum, Atatürk''ün aşağıdaki ilkelerinden hangisinin ete kemiğe bürünmüş (somutlaşmış) hâlidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-004 Soru Paketi.json (source id ITA-000061)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('5a3bfe68-7116-50b5-ba8f-6dfa08ea8352', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '1909 yılında Meşrutiyet yönetimine karşı İstanbul''da çıkarılan 31 Mart İsyanı, Selanik''ten yola çıkan ve kurmay başkanlığını Mustafa Kemal''in yaptığı Hareket Ordusu tarafından bastırılmıştır. Bu olayın Türk siyasi tarihindeki en belirgin özelliği aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-004 Soru Paketi.json (source id ITA-000062)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('98f9cf22-51ac-58f8-9802-2fcb316bf08f', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '1908 yılında İttihat ve Terakki Cemiyeti''nin baskısıyla Padişah II. Abdülhamit''in II. Meşrutiyet''i ilan etmesi, Osmanlı Devleti''nde demokratikleşme adına önemli bir adımdır. Ancak bu iç kargaşa ve otorite boşluğu ortamında fırsattan istifade eden bazı devletler Osmanlı''ya karşı toprak kazanımları elde etmiştir. Aşağıdakilerden hangisi II. Meşrutiyet''in ilanı sırasındaki otorite boşluğunda yaşanan bu kayıplardan biri değildir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-004 Soru Paketi.json (source id ITA-000063)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('72d3fa7b-a045-57a8-98d0-b4a0199db5cd', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'I. Dünya Savaşı''nda Almanya''nın teşvikiyle açılan Kanal Cephesi''nde Osmanlı ordusu Cemal Paşa komutasında Süveyş Kanalı''nı ele geçirmeyi hedeflemiştir. Yönetsel ve jeopolitik strateji (sistem okuryazarlığı) açısından İttifak Devletleri''nin bu cepheyi açmasındaki asıl amaç aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-004 Soru Paketi.json (source id ITA-000064)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('31fc9086-222d-5e55-8a98-285d562c3877', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'I. Dünya Savaşı sırasında Irak Cephesi''nde, Halil (Kut) Paşa komutasındaki Osmanlı birliklerinin General Townshend komutasındaki İngiliz ordusunu kuşatarak yaklaşık 13 bin askeriyle birlikte esir aldığı, İngiliz askerî tarihine büyük bir hezimet olarak geçen unutulmaz zafer aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-004 Soru Paketi.json (source id ITA-000065)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('9f218aa9-5615-563b-a5d3-328ed23b48e1', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Amasya Görüşmeleri''nin ardından yapılan seçimlerle toplanan Son Osmanlı Mebusan Meclisi''ne, Mustafa Kemal Paşa Erzurum mebusu olarak seçilmesine rağmen güvenlik nedeniyle katılamamıştır. Mustafa Kemal, meclise giden milletvekillerinden mecliste ''Müdafaa-i Hukuk'' adında bir grup kurmalarını istemiş, ancak milletvekilleri padişahın ve İtilaf Devletlerinin tepkisinden çekinerek bu isim yerine Rauf Orbay başkanlığında farklı bir grup kurmuşlardır. Kurulan bu siyasi grubun adı aşağıdakilerden hangisidir?', 'PUBLISHED')
