INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('8d6e26e1-bea6-5fac-8f7a-3e7f4ea44fdf', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Son Osmanlı Mebusan Meclisi tarafından 28 Ocak 1920''de kabul edilen Misak-ı Milli (Milli And), Millî Mücadele''nin siyasi, hukuki ve coğrafi programını belirleyen tarihi bir belgedir. Aşağıdakilerden hangisi Misak-ı Milli belgelerinde yer alan konulardan biri değildir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-004 Soru Paketi.json (source id ITA-000067)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('97cd417d-46d0-54ab-9ab4-6ca7f590d9cf', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '10 Ağustos 1920''de imzalanan Sevr Barış Antlaşması, Türk milletini Anadolu''da küçük bir bölgeye hapsetmeyi öngören son derece ağır şartlar içermekteydi. Ancak bu antlaşma, diplomatik literatürde hukuki olarak hiçbir zaman yürürlüğe girmemiş ve ''ölü doğmuş'' bir belge olarak nitelendirilmiştir. Sevr Antlaşması''nın hukuken geçersiz olmasının temel yasal (anayasal) gerekçesi aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-004 Soru Paketi.json (source id ITA-000068)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('f5d936e1-d9bf-528f-954a-afc7d325dcf7', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'I. TBMM''nin Anadolu''daki otoritesinin artması ve düzenli ordunun başarıları üzerine, İstanbul''daki Tevfik Paşa Hükûmeti, TBMM ile uzlaşma yolları aramak için Anadolu''ya bir heyet göndermiştir. 5 Aralık 1920''de Mustafa Kemal Paşa ile İstanbul Hükûmeti temsilcileri (Ahmet İzzet ve Salih Paşalar) arasında gerçekleşen ve İstanbul Hükûmeti''nin ''I. TBMM''yi hukuken tanıdığı'' diplomatik gelişme aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
