INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('e0b3e861-0cfd-51ef-80f6-e630c103c13f', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Millî Mücadele yıllarında Batı Cephesi''nde Kuvay-ı Milliye birliklerinin kaldırılarak emir komuta zincirine bağlı ''Düzenli Ordu''nun kurulması kararı alınmıştır. Bu kurumsallaşma adımına (hiyerarşik yapıya) karşı çıkarak isyan eden ve I. İnönü Savaşı sırasında düzenli orduyu hem Yunanlarla hem de kendi isyanıyla iki ateş arasında bırakan ünlü Kuvay-ı Milliye lideri aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-004 Soru Paketi.json (source id ITA-000070)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('2afb0438-aab1-5232-aeb4-4637efb4d8cf', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'I. İnönü Savaşı''nın ardından ordunun moralini yükseltmek için Millî Eğitim Bakanlığı (Maarif Vekâleti) tarafından bir İstiklal Marşı yarışması düzenlenmiştir. Başlangıçta ucunda para ödülü olduğu için bu yarışmaya katılmayan, ancak dönemin Millî Eğitim Bakanı Hamdullah Suphi (Tanrıöver) Bey''in iknasıyla şiirini yazan ve kazandığı para ödülünü ''Dar''ül Mesai'' adlı hayır kurumuna bağışlayarak erdemli bir davranış sergileyen millî şairimiz kimdir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-004 Soru Paketi.json (source id ITA-000071)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('74e483a1-fd47-57e7-8963-b930408c419c', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'I. TBMM tarafından savaşın en yoğun olduğu dönemde kabul edilen 1921 Anayasası (Teşkilat-ı Esasiye), sadece 23 maddeden oluşan kısa ve öz bir metin olup kişi hak ve hürriyetlerine yer vermemiştir. Hukuk sosyolojisi ve olağanüstü kriz dönemi yönetimi bağlamında, 1921 Anayasası''nda temel kişi haklarına yer verilmemesinin temel nedeni aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-004 Soru Paketi.json (source id ITA-000072)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('2110eac6-5377-5ca3-b9aa-077d939e337e', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '26 Ağustos 1922''de başlayan Büyük Taarruz, 30 Ağustos''taki Dumlupınar (Başkomutanlık) Meydan Muharebesi ile kesin bir zafere dönüşmüştür. Bu muharebenin ardından Başkomutan Mustafa Kemal Paşa''nın, bozguna uğrayarak kaçan Yunan ordusunu tamamen Anadolu''dan atmak ve ordunun yönünü belirlemek için verdiği ünlü stratejik emir aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-004 Soru Paketi.json (source id ITA-000073)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('a862ac1a-65df-5f81-be39-fadbbcc2e3c2', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Büyük Taarruz''un başarısıyla İtilaf Devletleri mütareke talebinde bulunmuş ve 11 Ekim 1922''de Mudanya Ateşkes Antlaşması imzalanmıştır. Bu antlaşmanın askerî ve diplomatik başarısı sayesinde, Türk ordusu tek bir kurşun dahi atmadan (savaşsız olarak) aşağıdaki bölgelerden hangilerini işgalden kurtarmıştır?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-004 Soru Paketi.json (source id ITA-000074)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('050df71f-6ff6-5471-8381-1617b510b829', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Türkiye Cumhuriyeti''nde çok partili hayata geçişin ikinci denemesi olan Serbest Cumhuriyet Fırkası (1930), bizzat Atatürk''ün isteğiyle, hem hükûmeti denetleyecek bir muhalefet yaratmak hem de 1929 Dünya Ekonomik Buhranı''nın etkilerine karşı liberal ekonomik politikalar geliştirmek amacıyla kurulmuştur. Bu partinin kurucusu ve genel başkanı olan deneyimli devlet adamı aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-004 Soru Paketi.json (source id ITA-000075)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('b6b1441e-3ab1-544f-8b59-18d6c53f95b6', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Atatürk, çağdaşlaşma hedefleri doğrultusunda 1925 yılında Kastamonu''da Şapka İnkılabı''nı tanıtmış ve ardından yasal düzenleme yapılmıştır. Bu inkılabın görünürdeki amacı çağdaş bir dış görünüm sağlamak iken, sosyolojik felsefesi toplumdaki dinî ve sınıfsal statü (ayrıcalık) belirten kılık kıyafet farklılıklarını ortadan kaldırmaktı. Bu yönüyle Şapka İnkılabı, Atatürk''ün İnkılapçılık ilkesinin yanı sıra doğrudan hangi ilkesiyle de sıkı sıkıya bağlantılıdır?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-004 Soru Paketi.json (source id ITA-000076)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('ce108696-8549-558b-a880-bf6ce47b70c9', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Atatürk döneminde, Türk tarihini sadece Osmanlı ve İslam dönemiyle sınırlayan ümmetçi tarih anlayışından vazgeçilerek 1931''de Türk Tarih Kurumu; Türk dilini yabancı dillerin boyunduruğundan kurtarmak ve zenginliğini ortaya çıkarmak için 1932''de Türk Dil Kurumu kurulmuştur. Bu iki kurumun açılması, Atatürk''ün hangi ilkesinin kurumsallaşmasına yönelik atılmış en net adımlardır?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-004 Soru Paketi.json (source id ITA-000077)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('f55f7495-2a27-58f8-9f3b-0410b6bfe523', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Atatürk ilkeleri, dogmatik (donmuş ve değişmez) bir yapıya sahip değildir. Toplumun ihtiyaçlarına göre bilimin ve aklın rehberliğinde sürekli yenilenmeyi, çağdaş medeniyetler seviyesinin üzerine çıkmayı ve statükoculuğu (mevcut durumu körü körüne korumayı) reddetmeyi savunan dinamik Atatürk ilkesi aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-004 Soru Paketi.json (source id ITA-000078)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('feae398e-c044-5aac-94aa-b08c51f3c3b8', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '1930''lu yılların sonlarına doğru Akdeniz''de kimliği belirsiz denizaltıların (özellikle İtalya''ya ait olduğu bilinen) ticari gemilere saldırması ve korsanlık faaliyetlerinde bulunması üzerine, bölge güvenliğini sağlamak amacıyla 1937 yılında uluslararası bir konferans düzenlenmiştir. Türkiye''nin de katılarak Akdeniz''in güvenliğine katkı sunduğu bu antlaşma aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-004 Soru Paketi.json (source id ITA-000079)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('4ab07498-0ef7-53f9-bbb2-9f3c5d2c195d', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', '1926 yılında Ege Denizi''nde ''Bozkurt'' adlı Türk gemisi ile ''Lotus'' adlı Fransız gemisinin çarpışması sonucu yaşanan can kayıpları üzerine, Türkiye''nin Fransız kaptanı tutuklayıp yargılaması uluslararası bir krize neden olmuştur. Konunun Lahey Sürekli Adalet Divanı''na taşınması ve Türkiye''nin dönemin Adalet Bakanı Mahmut Esat (Bozkurt) Bey tarafından savunularak davayı kazanması, genç Cumhuriyetin hangi özelliğini uluslararası arenada ispatlamıştır?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\ITA-004 Soru Paketi.json (source id ITA-000080)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('a19bc04f-d043-5726-b3cc-aec8c43f9fbe', '27372eac-908b-54d8-b8f9-77b260c7d060', '93ae961b-b954-5967-b4cf-94012cca3276', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli''nin bilgi ve bilgelik hedeflerine paralel olarak Atatürk döneminde, geri kalmış ve yeniliklere ayak uyduramayan eski eğitim kurumu ''Darülfünun'' kapatılmış; yerine İsviçreli Profesör Albert Malche''nin hazırladığı rapor doğrultusunda 1933 yılında modern, bilimsel özerkliğe ve çağdaş araştırma yöntemlerine sahip hangi eğitim kurumu açılmıştır?', 'PUBLISHED')
