INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('b1ffba47-29c8-575d-8bd5-22d080ad402a', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Eğitim yönetimi literatürüne göre örgüt kültürü; sosyalleşme süreci içinde çalışanlara, karşılaşılan sorunların nasıl ele alınacağı ve çözüleceği konularında genel davranış kalıpları sunar. Bu tanımlamadan hareketle, ''güçlü ve pozitif bir örgüt kültürüne'' sahip bir okulda okul müdürünün yönetim pratiği açısından aşağıdaki avantajlardan hangisini elde etmesi beklenir?', 'PUBLISHED')
