-- source: D:\EKYS\content\questions\draft\EB-001 Soru Paketi.json (source id EB-000002)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('d678a00b-b0d9-5649-9d71-551480380287', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir lise müdürü, günümüz eğitim kurumlarının tek bir kişinin yönetemeyeceği kadar karmaşık bir yapıya sahip olduğuna inanmaktadır. Bu nedenle okulun akademik gelişim planlamasını zümre başkanlarına, kriz müdahale stratejilerini rehberlik servisine ve sosyal etkinlik kararlarını öğrenci meclisine devretmiştir. Sorumlulukların uzmanlık alanlarına göre paylaşıldığı bu yönetsel yaklaşım, aşağıdaki çağdaş liderlik türlerinden hangisiyle adlandırılır?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\EB-001 Soru Paketi.json (source id EB-000003)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('ba881716-28a9-5909-8e83-d6639cc4ab95', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Eğitim yönetiminde lider, sadece mevcut düzeni sürdüren bir idareci olmamalıdır. Kurumu mevcut durağan (statüko) durumundan alıp gelecekteki ideal bir noktaya taşıyan, kurum için yeni bir vizyon oluşturan ve öğretmenleri bu vizyon etrafında kenetleyerek onlara ilham veren liderlik tarzı aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\EB-001 Soru Paketi.json (source id EB-000004)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('5d754f70-c61d-57b2-8996-a2c8dec905d0', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli, Kartezyen felsefenin insan zihnini ve bedenini birbirinden bağımsız parçalar olarak gören ikici (dualist) yaklaşımını reddeder. Bunun yerine eğitimin, insanın zihinsel, duygusal ve fiziksel gelişimini eş zamanlı desteklemesi gerektiğini savunur. Modelin felsefi altyapısında yer alan ve ''Ruh ve Beden'' uyumunu ifade eden bu bütünlük alanı aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
