INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('edc3af8d-e532-5c8a-be45-216bad3bb59c', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Sistem okuryazarlığı, karmaşık yapıları parçalara ayrılmış izole birimler olarak değil, organik bir bütün olarak görebilme ve yönetebilme becerisidir. Buna göre, bir öğrencinin sistem okuryazarlığı sürecinde ulaşması beklenen en üst düzey (nihai) bilişsel aşama aşağıdakilerden hangisidir?', 'PUBLISHED')
