INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('f566c618-7fb0-546d-b632-9a5a1aff0439', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir öğretmen, araştırma ödevi hazırlayan öğrencilerinden dijital platformlarda buldukları bilgileri doğrudan kopyalamamalarını, bilgi toplamak için uzman kişilere veya güvenilir genel ağlara başvurmalarını ve kullandıkları her metnin veya görselin gerçek yazarını/üreticisini kaynakçada mutlaka belirtmelerini istemiştir. Öğretmenin bu yönlendirmesi, Maarif Modeli''ndeki dijital okuryazarlığın hangi süreç bileşenini geliştirmeye yöneliktir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
