INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('c8d2a8c7-de3e-5598-a33a-4ab02f7cc716', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Günümüz eğitim sistemlerinde ''Kapsamlı Gelişimsel Rehberlik Modeli'' uygulanmaktadır. Bu model, rehberliği bir kriz müdahalesi olmaktan çıkarıp tüm eğitim sürecine entegre etmiştir. Aşağıdakilerden hangisi Gelişimsel Rehberlik Modeli''nin temel özelliklerinden veya varsayımlarından biri **değildir**?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
