INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('73c606e6-6b1c-5345-a423-2b2867fb17cc', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir öğretmen, dersin 40 dakikalık süresinin yaklaşık 10 dakikasını yoklama alma, materyal dağıtma ve sınıfın dikkatini toplama gibi rutin işlere harcamaktadır. Daha sonra bu rutinleri hızlandırmak için öğrencilere belirli görevler dağıtmış ve derse geçiş süresini kısaltarak öğrencilerin doğrudan konuya odaklandığı ve başarılı bir şekilde etkinliğe dâhil olduğu süreyi artırmıştır. Öğretmenin artırmayı başardığı bu zaman türü literatürde nasıl adlandırılır?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
