INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('66fb3efe-c1bf-5fec-913e-3146482bc9aa', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Yeni atandığı okulda müdür olan Aslı Hanım, eğitim-öğretim yılı başlamadan önce okulun fiziksel alanlarındaki kör noktaları tespit ettirmiş, siber zorbalık konusunda velilere yönelik bir seminer planlamış ve acil durum tahliye protokollerini güncelleyerek öğretmenlere simülasyon eğitimi verdirmiştir. Aslı Hanım''ın okul güvenliği bağlamında uyguladığı bu yönetsel strateji aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\EB-001 Soru Paketi.json (source id EB-000010)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('f35207c8-0e59-55b1-8d2a-0525ae9b93eb', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Öğrenciler, bir sosyal bilimler projesi kapsamında yaşadıkları ilçenin son beş yıllık yağış miktarlarına dair ham verileri TÜİK veritabanından çekmişlerdir. Daha sonra bu sayısal yığınları, sınıftaki diğer öğrencilerin ilk bakışta anlayabilmesi için ''çubuk grafiklere'' ve ''renklendirilmiş bölgesel ısı haritalarına'' dönüştürmüşlerdir. Bu eylem, TYMM Beceriler Çerçevesindeki veri okuryazarlığının hangi süreç bileşenini yansıtır?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\EB-001 Soru Paketi.json (source id EB-000011)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('8fbc1b89-43f0-5249-8774-57940b5db808', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Eğitim felsefesi ve bilim tarihi açısından eşsiz bir miras bırakan; Aristo''nun mantık felsefesini geliştirerek Avrupa''ya tanıtan, seslerin matematiksel ölçümünü yaparak müziği bilimsel bir temele oturtan ve Batı dünyasında ''Muallim-i Sani'' (İkinci Öğretmen) olarak bilinen ünlü Türk-İslam düşünürü kimdir?', 'PUBLISHED')
