INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('ef7e99d5-f35b-55ef-b501-b9033f541476', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Klasik dönemde Sahn-ı Seman ve Süleymaniye gibi zirve kurumlara sahip olan Osmanlı medrese sistemi, 17. yüzyıldan itibaren bozulmaya başlamıştır. Eğitim sisteminde liyakatin tamamen terk edilerek, ilmî rütbelerin (müderrislik vb.) babadan oğula geçmesini meşrulaştıran ve ''âlimin oğlu âlimdir'' anlayışıyla çocuk yaştaki kişilere akademik unvanların dağıtılmasına yol açan yozlaşmış sisteme ne ad verilir?', 'PUBLISHED')
