INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('084cf5f6-7dd1-5489-bc16-1a02c3447e9b', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Okul müdürü, nöbet görevlerine sürekli geç kalan bir öğretmene, ''Sen her zaman böylesin, hiçbir zaman sorumluluklarının bilincinde değilsin ve kuralları asla umursamıyorsun!'' diyerek tepki göstermiştir. Bu iletişim tarzı, öğretmenin savunmaya geçmesine ve çatışmanın büyümesine yol açmıştır. Müdürün etkili bir sınıf/okul yönetimi bağlamında bu yargılayıcı ''Sen Dili'' yerine kullanması gereken ''Ben Dili''ne en uygun ifade aşağıdakilerden hangisidir?', 'PUBLISHED')
