INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('5a965e3e-eeda-5d21-8472-01b0cf405046', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir okul müdürü, öğretmenlerin hiçbir işine karışmamakta, ''herkes ne yapacağını bilir'' mantığıyla karar alma süreçlerini tamamen onlara bırakmakta ve kendisinden talep edilen idari onayları sürekli ertelemektedir. Çalışanların bağımsızlıklarına sonsuz alan tanıyan ancak ihtiyaç anında destek sunmayan bu liderlik tarzı, eğitim yönetimi literatüründe nasıl adlandırılır?', 'PUBLISHED')
