INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('e457d562-108d-57ec-83b8-70f1e3eda877', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Hafif düzeyde otizm spektrum bozukluğu tanısı alan bir öğrenci, akranlarıyla birlikte eğitim görebilmesi amacıyla bir genel eğitim sınıfına (kaynaştırma/bütünleştirme uygulaması) yerleştirilmiştir. Bu öğrencinin akademik, sosyal ve uyum becerilerinin gelişimini sağlamak üzere okulun BEP Geliştirme Birimi tarafından hazırlanması zorunlu olan yol haritası (belge) aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\EB-001 Soru Paketi.json (source id EB-000016)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('af90eee4-64ff-5e19-b9a1-ac1c3420e238', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir öğrenci, karşısına çıkan karmaşık bir matematiksel problemi çözebilecek yüksek bir ''kavramsal beceriye'' (bilişsel güce) sahiptir; ancak bu becerisini kullanması için içsel bir arzu, merak ve yeni durumlara karşı bir hazırbulunuşluk hissetmesi gerekmektedir. Türkiye Yüzyılı Maarif Modeli Beceriler Çerçevesi''ne göre, becerileri harekete geçiren bu ''içsel katalizör'' (örneğin merak, açık fikirlilik) kavramı aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\EB-001 Soru Paketi.json (source id EB-000017)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('afe8c55d-da6d-52fe-acf9-82a1fb98e312', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir okulda öğretmenler kendi aralarında yüksek bir iş birliğine sahiptir; okul müdürü bürokratik engeller çıkarmak yerine personeline güvenmekte ve onların mesleki gelişimlerini desteklemektedir. Bu okulda öğretmenlerin iş doyumu yüksek, yabancılaşma hissi ise düşüktür. Örgüt iklimi sınıflandırmalarına göre bu okulda hâkim olan iklim türü aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
