INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('8e666775-5a12-5fb2-9580-ee2a95ddcc78', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Eğitimin nihai amacı salt bilişsel bilgi depolamak değil; değer üreten, doğayı ve sanatı takdir edebilecek bir estetik zevke sahip olan, neyin iyi neyin kötü olduğunu ayırt edebilen yüksek bir ahlaki bilince ulaşmaktır. Türkiye Yüzyılı Maarif Modeli''nde bu etik (ahlak) ve estetik algısını merkeze alan bütünlük alanı aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\EB-001 Soru Paketi.json (source id EB-000019)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('abad1b4e-cacc-5e74-b7a4-ed39bac9b0e6', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Ders işlenişi sırasında bir öğrenci elindeki kalemi sıraya hafifçe vurarak ses çıkarmaktadır. Bu ses öğretmeni rahatsız etse de, öğrencinin bu davranışı dikkat çekmek için yaptığını anlayan öğretmen, dersin akışını bozmamak ve öğrenciye istediği ilgiyi vermemek adına hiçbir şey olmamış gibi konuyu anlatmaya devam etmiştir. Bir süre sonra öğrenci kalemi vurmayı bırakmıştır. Öğretmenin istenmeyen bu davranışa karşı kullandığı strateji aşağıdakilerden hangisidir?', 'PUBLISHED')
