INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('c6a89d46-3be7-5900-bdf2-3063c26c45e2', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir eğitim kurumu yöneticisinin, zamanının büyük bir kısmını evrak işlerine veya binanın fiziki bakımı gibi bürokratik işlemlere ayırmak yerine; doğrudan sınıflardaki öğretim süreçlerine, müfredatın uygulanmasına, öğretmenlerin pedagojik mesleki gelişimine ve öğrenci başarısını artırmaya odaklanmasını ifade eden liderlik tarzı aşağıdakilerden hangisidir?', 'PUBLISHED')
