INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('a03d5df3-6211-5efe-ae98-542d43931121', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Eğitim kurumlarında uygulanan çağdaş liderlik kuramlarından biri, liderin kendi çıkarlarından veya otoritesinden ziyade çalışanların (öğretmenlerin ve personelin) ihtiyaçlarına odaklandığı, onların kişisel ve mesleki gelişimlerini destekleyerek örgütsel başarıya ulaştığı yaklaşımdır. ''Önce insan'' felsefesine dayanan ve yöneticinin kendisini kuruma adadığı bu liderlik türü aşağıdakilerden hangisidir?', 'PUBLISHED')
