INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('f67abf9f-dc9d-559a-89c9-48ff89707d2d', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir okulda öğretmenler arasında güven eksikliği ve sert gruplaşmalar hâkimdir. Okul müdürü katı kurallar uygulayarak iletişimi tek yönlü (yukarıdan aşağıya) sürdürmekte, yenilikçi fikirleri reddederek sadece bürokratik işleyişe odaklanmaktadır. Personelin iş doyumu ve motivasyonu son derece düşüktür. Örgüt iklimi teorilerine (örneğin Halpin ve Croft) göre bu okulda aşağıdaki iklim türlerinden hangisi görülmektedir?', 'PUBLISHED')
