INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('9b229079-6c1b-56dd-ba1a-b5331cf3c45e', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Sınıf yönetimi sürecinde bir öğretmenin, kuralları ihlal ederek gürültü yapan bir öğrenciyi anında, adil ve net bir şekilde uyarması; sadece o öğrencinin değil, aynı zamanda sınıftaki fısıldaşan diğer öğrencilerin de davranışlarını olumlu yönde etkilemiş ve sınıfın genelinde sessizlik sağlanmıştır. Kounin''in sınıf yönetimi modeline göre, bir öğrenciye yönelik müdahalenin diğer izleyici öğrenciler üzerinde yarattığı bu etkiye ne ad verilir?', 'PUBLISHED')
