INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('d13a4418-2fd7-5fdf-a696-3946791f0199', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Frederick Herzberg''in ''Çift Faktör (Motivasyon-Hijyen) Kuramı''na göre, çalışanların iş tatminini belirleyen faktörler ikiye ayrılır. Bir okul müdürü, yeni eğitim yılında öğretmenler odasının fiziki şartlarını (mobilyalar, çay-kahve makineleri vb.) iyileştirmiş ve teknik altyapıyı yenilemiştir. Kurama göre, müdürün yaptığı bu fiziksel iyileştirmelerin (hijyen faktörleri) öğretmenler üzerindeki etkisi aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
