INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('7450a8d2-c8bd-5a86-9d42-b27e68c5a8ca', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir ortaokulda görev yapan okul psikolojik danışmanı, son yıllarda gençlerin dijital mecralardaki kullanım sürelerinin artması üzerine, okulda henüz herhangi bir zorbalık vakası yaşanmamasına rağmen tüm öğrencilere ve velilere yönelik ''Siber Zorbalıktan Korunma ve Dijital E-Güvenlik'' başlıklı seminerler düzenlemiştir. Bu çalışma, psikolojik danışmanlık ve rehberlik hizmetlerinin hangi temel işleviyle doğrudan ilgilidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
