INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('45f267ca-8ede-5097-9912-dc8d59e5debf', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Kaynaştırma/bütünleştirme uygulamaları kapsamında genel eğitim sınıflarında öğrenim gören özel eğitim ihtiyacı olan öğrencilerin, derslerindeki eksikliklerini gidermek ve potansiyellerini en üst düzeye çıkarmak amacıyla okul bünyesinde belirli derslerden birebir veya küçük gruplar hâlinde ek eğitim aldıkları özel düzenlenmiş ortamlara ne ad verilir?', 'PUBLISHED')
