INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('a456f265-4e2b-52fa-b6e4-a4e0c8b35a12', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir öğretmen, proje ödevini yapmayan ve dersin işlenişini aksatan öğrencisine ''Eğer bu projeyi yarına kadar teslim etmezsen, dönem sonu notunu sıfır vereceğim ve sınıfta kalmanı sağlayacağım!'' diyerek yüksek sesle tepki göstermiştir. Thomas Gordon''un ''Etkili İletişim'' modeline göre, öğretmenin bu ifadesi hangi tür iletişim engeline girmektedir?', 'PUBLISHED')
