INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('f2a3b8b3-87f1-5aaf-8231-d27e67fadf39', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Okul güvenliği ve kriz yönetimi literatürüne göre süreç; kriz öncesi (hazırlık), kriz anı (müdahale) ve kriz sonrası (iyileştirme) olmak üzere üç temel evreden oluşur. Aşağıdaki yönetsel eylemlerden hangisi bir eğitim kurumunda doğrudan ''krize müdahale (kriz anı)'' evresinde yapılması gereken işlemlerden biridir?', 'PUBLISHED')
