INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('3bb48fd0-8403-541d-82cd-11c52852be05', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir öğretmen, dersinde tüm öğrencilerin birbirinin yüzünü rahatlıkla görebilmesini, sınıf içi beyin fırtınası ve grup tartışmalarının aktif olarak yapılabilmesini ve kendisinin tüm öğrencilerle eşit düzeyde göz teması kurarak etkileşimi artırmayı hedeflemektedir. Öğretmenin bu pedagojik amaçlara ulaşabilmesi için tercih etmesi gereken en uygun sınıf oturma düzeni aşağıdakilerden hangisidir?', 'PUBLISHED')
