INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('bd8afdb8-1289-5701-851b-d4823361d2ca', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Açık sistem teorisine göre örgütler (okullar), dış çevreleriyle sürekli madde, enerji ve bilgi alışverişinde bulunarak hayatta kalırlar. Dış çevredeki teknolojik, yasal ve pedagojik değişimlere uyum sağlayamayan, yeniliklere kendini kapatan bir okul zamanla bozulmaya, dengesini yitirmeye ve enerjisini tüketerek çöküşe geçmeye başlar. Örgüt teorisinde sistemin bozulması ve düzensizliğe doğru gitmesi eğilimi hangi kavramla ifade edilir?', 'PUBLISHED')
