INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('c514068d-0f4d-554a-ac2d-70670cfbcf65', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Özel eğitim mevzuatına göre, kaynaştırma yoluyla eğitimlerine devam eden her öğrenci için okulda ''Bireyselleştirilmiş Eğitim Programı (BEP) Geliştirme Birimi'' kurulur. Aşağıdakilerden hangisi okulda kurulan bu birimin yasal ve zorunlu üyelerinden biri **değildir**?', 'PUBLISHED')
