INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('2e08be1f-45fe-5280-af28-203cf4e856f0', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir okul yöneticisi, zamanının büyük bir bölümünü evrak işleri veya bina bakımı gibi bürokratik işler yerine; sınıflardaki eğitim-öğretim süreçlerini gözlemlemeye, yeni müfredatın (Türkiye Yüzyılı Maarif Modeli) uygulanmasına rehberlik etmeye, öğretmenlerin mesleki gelişimini desteklemeye ve öğrenci başarısını izlemeye ayırmaktadır. Bu yöneticinin sergilediği çağdaş liderlik yaklaşımı aşağıdakilerden hangisidir?', 'PUBLISHED')
