INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('cf9914f8-bacb-5b37-a5ad-df2d013ab782', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir sınıf öğretmeni, okul kurallarına uyma konusunda yıl boyunca çok başarılı bir performans sergileyen ve verilen tüm görevleri eksiksiz yapan öğrencilerinden, dönemin son haftasında vermeyi planladığı zor ve yorucu olan ''dönem sonu ödevini'' iptal etmiştir (kaldırmıştır). Bu uygulamadan sonra öğrencilerin kurallara uyma davranışında bir sonraki dönem daha da artış görülmüştür. Öğretmenin kullandığı sınıf yönetimi/davranış değiştirme stratejisi aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
