INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('c376c4cf-d5d9-5039-99cb-094500a481d6', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Liderlik türleri arasında yer alan bir yaklaşımda lider; kurumun sahip olduğu inançları, geçmişten gelen gelenekleri, ritüelleri ve normları derinlemesine analiz eder. Ardından bu değerleri kurumun stratejik misyonuyla uyumlu hâle getirerek örgüte yeni bir kimlik ve aidiyet duygusu kazandırır. Semboller ve hikâyeler aracılığıyla örgüt iklimini şekillendiren bu liderlik türü aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
