INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('b84b8de4-4f33-5214-9937-856a31a82e79', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'İletişim sürecinde karşı tarafı doğru anlamak ve empati kurmak büyük önem taşır. Bir okul müdürünün, odasına şikâyet amacıyla gelen öfkeli bir veliyi dinlerken onunla göz teması kurması, sözünü kesmemesi, ''Anlatmak istediğiniz sanırım şu...'' diyerek velinin ifadelerini özetleyerek geri bildirimde bulunması ve duygularını anladığını hissettirmesi, aşağıdaki iletişim becerilerinden hangisine en iyi örnektir?', 'PUBLISHED')
