INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('ff4ef4ed-84c7-539f-a9a1-5a6c3d81fded', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir okulda her eğitim-öğretim yılının sonunda tüm öğretmenlerin ve personelin katılımıyla düzenlenen geleneksel veda yemeği, başarılı öğrencilere okulun simgesi hâline gelmiş özel bir rozet takılması ve pazartesi sabahları yapılan motivasyon konuşmaları, okul kültürünü güçlendirmektedir. Örgüt kültürü teorisine göre bu uygulamalar, kültürün hangi görünür (somut) ögesi kapsamında değerlendirilir?', 'PUBLISHED')
