INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('f445b404-ec43-5e59-b375-99b560208cb3', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Geleneksel rehberlik anlayışında hizmetler genellikle sadece problemli, uyum sorunu yaşayan veya akademik başarısızlık gösteren öğrencilere yönelik bir kriz müdahalesi olarak algılanırdı. Ancak çağdaş eğitim sistemlerinde benimsenen ''kapsamlı gelişimsel rehberlik'' anlayışında temel odak değişmiştir. Buna göre çağdaş rehberlik anlayışının dayandığı en temel ilke aşağıdakilerden hangisidir?', 'PUBLISHED')
