INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('7c8f5a44-985e-55db-ad95-f45c7f9bbe7c', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Okul müdürü Ali Bey, öğretmenler arasında ders dağılımı yaparken ve nöbet çizelgelerini hazırlarken kimseye ayrıcalık tanımamakta, yasalara ve hakkaniyete uygun davranmaktadır. İdari kararlarının arkasındaki gerekçeleri tüm personelle açıkça paylaşmakta ve kişisel yakınlıklarını işine asla karıştırmamaktadır. Ali Bey''in bu güvenilir ve adil tutumu, aşağıdaki liderlik kuramlarından hangisinin temel özelliklerini yansıtır?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
