INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('1dc9f894-bd78-5055-bb0c-603a9563c12c', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir ortaokulda 7. sınıf öğrencisi olan Cenk, sınıf arkadaşı Murat''ın izinsiz çektiği bir fotoğrafını üzerinde alaycı değişiklikler (montaj) yaparak sınıfın mesajlaşma gruplarında paylaşmış ve diğer arkadaşlarını da dijital platformlar üzerinden Murat''la konuşmamaları (dışlamaları) yönünde manipüle etmiştir. Eğitim kurumlarında sıkça karşılaşılan ve okul iklimini derinden bozan bu şiddet/zorbalık türü aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
