INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('ce3fe7f0-ba3c-5896-bd6c-1de2efc7785e', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Zaman yönetimi sınıf içindeki verimliliğin en kritik unsurudur. Bir öğretmenin dersin ilk 15 dakikasını sürekli olarak yoklama almaya, öğrencilerden ödev kâğıtlarını toplamaya, sınıfın fiziksel düzenini (pencereleri/perdeleri) ayarlamaya ayırması, dersin asıl hedeflerine ulaşılmasını engellemektedir. Sınıf yönetimi bağlamında, öğretmenin gereğinden fazla kullanarak öğrencilerin ''akademik öğrenme zamanını'' düşürdüğü bu zaman dilimi aşağıdakilerden hangisiyle ifade edilir?', 'PUBLISHED')
