INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('e1a0db0e-046d-5de9-bf38-1db64e26d58a', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Eğitim kurumlarında bir liderin otoritesi her zaman yasal (formel) statüden kaynaklanmaz. Liderin gücünün; onun olağanüstü kişisel özelliklerinden, sarsılmaz vizyonundan, hitabet yeteneğinden ve çalışanların (öğretmenlerin) ona duyduğu derin hayranlık ile gönüllü sadakatten kaynaklandığı liderlik kuramı aşağıdakilerden hangisidir?', 'PUBLISHED')
