INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('91093c0e-0d1e-565a-8389-20b4e0a6bd23', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli''ne göre; öğrencilerin gelir-gider dengesini kurması, bütçe yapmayı öğrenmesi, tüketim alışkanlıklarını ihtiyaçlarına göre ayarlaması ve tasarruf bilinci geliştirerek ekonomik kararlar alması, Beceriler Çerçevesi''nde yer alan hangi okuryazarlık alanının doğrudan hedefidir?', 'PUBLISHED')
