INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('d8563fe3-d5d4-5bed-8f37-eff498b1dc96', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Sınıf yönetimi uzmanı Jacob Kounin''in modellerine göre etkili bir öğretmenin sınıfın her köşesinde ne olup bittiğini bilmesi gerekir. Bir öğretmenin yüzü tahtaya dönük ve yazı yazarken bile en arka sırada notlaşan öğrencileri fark edip onları anında ismen uyarması, sınıfta ''öğretmenimizin ensesinde bile gözü var'' algısı yaratır. Öğretmenin sergilediği bu sınıf yönetimi becerisi aşağıdakilerden hangisidir?', 'PUBLISHED')
