INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('41b0c4eb-ed26-5297-964c-502408a909f9', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Sınıf arkadaşıyla kavga ettiği için çok üzgün olan ve bu durumu ağlayarak öğretmeniyle paylaşan bir öğrenciye öğretmeni: ''Senin yerinde olsam hemen gider ondan özür dilerdim, böyle yaparsan aranızdaki sorunu hemen çözersin ve bir daha üzülmezsin.'' demiştir. Thomas Gordon''un Etkili İletişim modeline göre öğretmenin bu yaklaşımı hangi iletişim engeline örnektir?', 'PUBLISHED')
