INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('2303ca25-93e4-57ac-9c50-22e8053379b7', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Okul psikolojik danışmanının, öğrencilerin yetenek testleri, ilgi envanterleri ve akademik başarı sonuçlarına dayanarak onları yeteneklerine en uygun seçmeli derslere, sosyal kulüplere veya mezuniyet sonrasında uygun bir üst eğitim kurumuna (meslek lisesi, fen lisesi vb.) yerleşmeleri konusunda desteklemesi, rehberliğin hangi temel işleviyle açıklanır?', 'PUBLISHED')
