INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('da7a7fa5-e26b-5c68-b2d8-c8960bac7890', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Yeni eğitim öğretim yılının başında okul müdürü; okulda yaşanabilecek olası acil durumlar için öğretmenlerden, güvenlik görevlilerinden ve okul hemşiresinden oluşan bir ''Krize Müdahale Ekibi'' kurmuş, okulun güncel krokilerini hazırlatarak acil toplanma alanlarını belirlemiş ve herkesin görev tanımını yazılı olarak tebliğ etmiştir. Kriz yönetimi döngüsüne göre okul müdürünün bu faaliyeti hangi aşamanın kapsamındadır?', 'PUBLISHED')
