INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('94cdee2d-c716-5ca1-8f91-31b4500d5456', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Özel eğitim ihtiyacı olan bir öğrencinin kaydı okul bünyesindeki ''özel eğitim sınıfında'' bulunmaktadır. Öğrenci günün büyük bölümünü bu sınıfta geçirmekte; ancak beden eğitimi, görsel sanatlar ve müzik gibi bazı uygulamalı derslerde normal gelişim gösteren akranlarının bulunduğu genel eğitim sınıfına katılarak onlarla birlikte eğitim almaktadır. Uygulanan bu eğitim modeline ne ad verilir?', 'PUBLISHED')
