INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('77adf4ff-5cd7-5155-9cdf-54d863f76fe8', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Halpin ve Croft''un okul iklimi tiplerine göre; okul müdürünün tamamen iş ve görev odaklı olduğu, kuralları çok sıkı bir şekilde işlettiği ancak öğretmenlerle arasında samimi, babacan veya destekleyici hiçbir sosyal ilişkinin bulunmadığı bir okul ortamı tasvir edilmektedir. Öğretmenler verilen işleri mekanik bir şekilde yapsalar da moralleri düşüktür ve müdüre karşı mesafelidirler. Bu özelliklere sahip örgüt iklimi aşağıdakilerden hangisidir?', 'PUBLISHED')
