INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('076ea48f-5abe-565c-aea3-2ea00b0848b0', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Okulunda uzun yıllardır çalışan, meslektaşları tarafından sevilen, ekonomik bir kaygısı olmayan ve idareciler tarafından saygı duyulan kıdemli bir öğretmen; hiçbir ek ücret veya takdir beklentisi olmaksızın, sadece içsel potansiyelini zirveye taşımak ve eğitim dünyasına yeni bir pedagojik model kazandırmak amacıyla yorucu bir akademik kitap yazma sürecine girmiştir. Maslow''un İhtiyaçlar Hiyerarşisi''ne göre öğretmenin bu davranışı hangi ihtiyacını karşılamaya yöneliktir?', 'PUBLISHED')
