INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('b7bf8a14-cd53-550c-8ff7-4dd6b91f97d7', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Doğal kaynakların sınırsız olmadığını fark ederek okulda sıfır atık projesi başlatan, kendi karbon ayak izini azaltmak için enerji tasarrufu yapan ve şimdiki kararlarının gelecek nesillerin yaşam alanını tehlikeye atmaması gerektiği bilinciyle (ekolojik dengeyi koruyarak) hareket eden bir öğrenci grubu, TYMM''ye göre hangi okuryazarlık alanında gelişim göstermiştir?', 'PUBLISHED')
