INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('620b07e4-ec9d-5221-b232-eeec949b1524', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir öğretmen, derste matematik etkinlik kâğıtlarını çözmekte isteksiz olan öğrencilerine, ''Eğer çalışma kâğıtlarınızı sessizce ve eksiksiz tamamlarsanız, dersin son on dakikasında çok sevdiğiniz grup zeka oyununu oynayabilirsiniz.'' demiştir. Öğrenciler bu vaat üzerine kâğıtları hızla çözmüştür. Sınıf yönetiminde daha az tercih edilen bir davranışın yapılmasını sağlamak için çok sevilen bir etkinliğin koşul (pekiştireç) olarak sunulması hangi ilkeyle açıklanır?', 'PUBLISHED')
