INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('2d03afbc-1539-519b-901e-19b35e79a007', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Yeni eğitim yılı başında okula yeni atanan stajyer öğretmenlere yönelik düzenlenen uyum toplantısında; okul müdürü tarafından yıllar önce bu okulda görev yapmış fedakâr bir öğretmenin, kışın metrelerce karda yürüyerek okula yakacak odun taşıdığı ve öğrencileri soğuktan koruduğu anlatılarak kurumsal aidiyet ruhu aşılanmaktadır. Bu anlatılar, örgüt kültürünün hangi somut ögesini oluşturur?', 'PUBLISHED')
