INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('e3a80a8b-cd6a-5ef2-8bc9-456099a8dff6', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir sınıf öğretmeni, sınıfındaki klikleri (alt gruplaşmaları), lider öğrencileri, dışlanan (izole) öğrencileri ve karşılıklı çeken/iten ilişkileri tespit edebilmek amacıyla öğrencilere ''Sınıfta bir çalışma grubunda yer almak istediğiniz üç arkadaşınızı sırasıyla yazınız.'' şeklinde bir form uygulamış ve sonuçları bir grafiğe dökmüştür. Öğretmenin uyguladığı bu bireyi tanıma tekniği aşağıdakilerden hangisidir?', 'PUBLISHED')
