INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('8418ef6b-7a81-509b-b9aa-442335e0f3ae', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Dönüşümcü (transformasyonel) liderlik kuramı dört temel boyuttan oluşur. Bir okul müdürü, öğretmenlerinin sürekli aynı (geleneksel) yöntemlerle ders anlatmasını engellemek için onları eleştirel düşünmeye, eski varsayımları sorgulamaya, sorunlara yenilikçi (inovatif) ve yaratıcı çözümler bulmaya teşvik etmektedir. Müdürün öğretmen zihinlerinde yarattığı bu etki, dönüşümcü liderliğin hangi boyutuyla ifade edilir?', 'PUBLISHED')
