INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('2ee74464-2647-51fb-8be4-0272baf3b874', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli Sosyal-Duygusal Öğrenme Becerilerinde ''Ortak/Birleşik Beceriler'' yer almaktadır. Bir öğrencinin harekete geçmeden önce eyleminin olası sonuçlarını etik standartlar çerçevesinde değerlendirmesi, eylemin hem kendisine hem de topluma (çevresine) sağlayacağı fayda ve zararları göz önünde bulundurarak seçimler yapmasını ifade eden beceri aşağıdakilerden hangisidir?', 'PUBLISHED')
