INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('b93684ac-2cf5-5dcf-87b5-82fd76eec82a', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir okulda bazı büyük yaş grubu öğrenciler, alt sınıflardaki daha küçük öğrencileri okul köşelerinde sıkıştırarak tehdit etmekte, onların öğle yemeği için getirdikleri harçlıklarını zorla ellerinden almakta veya kantinden kendilerine ücretsiz yiyecek aldırmaktadır. Öğrencilerin mal varlığına el koyan bu şiddet türü, zorbalık sınıflandırmasında nasıl adlandırılır?', 'PUBLISHED')
