INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('bc941519-fe0d-5028-8fac-2505fa457dc7', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'TYMM Veri Okuryazarlığı (OB7) sürecinde olan bir öğrenci grubu, okuldaki beslenme alışkanlıklarını ölçmek amacıyla ilk sorularını belirledikten sonra bir bilimsel araştırma metodolojisi tasarlamış, ölçüm için anket formları hazırlamış ve bizzat sahaya inerek (sınıfları gezerek) anket verilerini (ham veriyi) toplamıştır. Öğrencilerin gerçekleştirdiği bu işlemler, veri okuryazarlığının hangi süreç bileşenidir?', 'PUBLISHED')
