INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('e1d8f489-1d2a-5fdd-9fda-2929313b485b', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Selçuklu ve Osmanlı eğitim sisteminin en önemli parçası olan esnaf teşkilatında (Ahilik ve Lonca); çıraklıktan ustalığa geçiş sürecinde sadece mesleki ve teknik bilgiler değil, aynı zamanda doğruluğun, cömertliğin ve iş ahlakının kuralları da öğretilmekteydi. Ahilik teşkilatının bu mesleki ahlak ve nizam kurallarının yazılı olduğu temel belgelere/kitaplara ne ad verilirdi?', 'PUBLISHED')
