INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('065643ca-eaea-5481-ac6b-57856a563b19', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'İlk Türk devletlerinde (Hunlar, Göktürkler vb.) eğitim, dört duvarı olan kurumsal okullardan ziyade yaşamın içindeki destanlar, atasözleri ve töre kuralları etrafında şekillenmiştir. Devlet ile millet arasındaki karşılıklı sorumlulukları, ideal yönetici niteliklerini anlatan ve Türk tarihinin bilinen ilk yazılı, siyasal ve pedagojik eseri (nasihatnamesi) kabul edilen metin aşağıdakilerden hangisidir?', 'PUBLISHED')
