INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('a66c1c88-c8c7-5c1d-be1c-1be3c82d38d8', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Örgüt kültürü sadece gözle görülen ritüellerden veya kurumsal sembollerden ibaret değildir. Edgar Schein''ın kültür modeline göre; çalışanların ''Biz kimiz?'', ''Burada insanlara nasıl davranılır?'' gibi sorulara verdikleri, çoğu zaman tartışılmayan, yazılı olmayan ancak herkesin bilinçaltında doğru kabul ettiği en derin ve görünmez kültür katmanı aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\EB-005 Soru Paketi.json (source id EB-000083)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('39ee2eef-bdfc-5191-a6c2-48b6abad32ad', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Sınıf yönetiminde zamanın verimli kullanılması esastır. Bir dersin 40 dakikalık toplam süresi ''Ayrılmış Zaman'' olarak adlandırılır. Öğretmenin derse girip yoklama alma, materyalleri hazırlama ve ödevleri toplama gibi bürokratik (rutin) işlemleri bitirdikten sonra; fiilen ders konusunu anlatmaya ve sınıf içi eğitsel etkinlikleri yönetmeye ayırdığı net süreye ne ad verilir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
-- source: D:\EKYS\content\questions\draft\EB-005 Soru Paketi.json (source id EB-000084)
INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('92c31231-fd26-5546-a62c-0f7fc9f0fff8', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Dönüşümcü (transformasyonel) liderlik yaklaşımında lider, öğretmenlerine hitap ederken anlamlı ve vizyoner hedefler koyar. Okul müdürü Zeynep Hanım, dönem başı toplantısında öğretmenlerine: ''Bizler sadece ders anlatan memurlar değiliz; bizler bu ülkenin geleceğini elleriyle inşa eden mimarlarız, sizlerin gayretiyle bu okul Türkiye''nin en iyi eğitim yuvası olacak!'' diyerek takım ruhunu ve coşkuyu artırmıştır. Müdürün bu yaklaşımı dönüşümcü liderliğin hangi boyutuyla ifade edilir?', 'PUBLISHED')
