INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('dedc2466-0519-5548-9b28-c73b14645bbb', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bilişim teknolojileri öğretmeni, öğrencilerine dijital ortamlarda hazırladıkları ortak proje ödevlerini bulut sistemine yüklerken yetkisiz erişimleri engellemek için dosyalarını şifrelemelerini ve emeklerinin kaybolmaması için mutlaka yedekleme yapmalarını tavsiye etmiştir. TYMM Beceriler Çerçevesi''ne göre öğretmenin bu yönlendirmesi, Dijital Okuryazarlığın (OB2) hangi alt süreç bileşeniyle doğrudan ilgilidir?', 'PUBLISHED')
