INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('d7680e14-cf00-5930-9c99-36aaa46dfe91', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Okullarda açılan ''Destek Eğitim Odası'', sadece zihinsel, işitsel veya fiziksel yetersizliği olan öğrencilere yönelik bir hizmet birimi değildir. Özel eğitim mevzuatına ve kapsayıcı eğitim uygulamalarına göre, aşağıdaki öğrenci gruplarından hangisi de genel eğitim sınıflarına devam ederken sahip olduğu yüksek potansiyeli değerlendirmek amacıyla destek eğitim odasından yararlanma hakkına sahiptir?', 'PUBLISHED')
