INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('a9c3c633-76ce-5a23-adf7-1e076da6dc9f', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Üniversite sınavı yaklaşırken aşırı kaygı yaşadığını, nefes darlığı çektiğini ve geceleri uyuyamadığını söyleyen 12. sınıf öğrencisine, okul müdürü: ''Sen şimdi bunları boşver, havalar da güzelleşti, yaklaşan bahar şenliklerinde sınıf olarak hangi gösteriyi yapacaksınız, ondan haber ver!'' şeklinde bir tepki göstermiştir. Thomas Gordon''un Etkili İletişim Modeline göre, yöneticinin bu tepkisi hangi iletişim engeline örnektir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
