INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('957b75e2-2a64-54cb-b995-d5052bb03e3b', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Okullarda yaşanan her tartışma, fikir ayrılığı veya kavga pedagojik anlamda ''zorbalık'' olarak nitelendirilmez. Bir davranışın akran zorbalığı (bullying) olarak tanımlanabilmesi ve ona göre müdahale edilebilmesi için eylemin belirli bilimsel kriterleri taşıması gerekir. Aşağıdakilerden hangisi bir davranışın zorbalık sayılabilmesi için aranan temel şartlardan biri **değildir**?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
