INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('08c67981-601e-573f-a491-4962bdad7467', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir lise sınıfındaki öğrencilere ''Küresel Isınmanın Etkileri'' konulu dijital bir sunum hazırlama ve bunu uluslararası bir platformda canlı olarak sunma görevi verilmiştir. Öğrenciler hemen işe koyulmadan önce, sunumu yapabilmek için hangi bilgisayar programlarına, hangi çevrim içi veri tabanlarına, nasıl bir mikrofona ve ne kadarlık bir internet hızına ihtiyaçları olduğunu listeleyerek işe başlamışlardır. TYMM Beceriler Çerçevesi''ne göre bu hazırlık aşaması hangi dijital okuryazarlık sürecidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
