INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('65a8fdeb-8b2f-5c60-8dde-b92d1455e723', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Osmanlı Devleti''nde medrese eğitimi, devletin büyümesiyle birlikte yüzyıllar boyunca sürekli gelişim göstermiş ve hiyerarşik bir akademik yapıya kavuşmuştur. Fatih Sultan Mehmet döneminde kurulan Sahn-ı Seman Medreselerinden sonra; Kanuni Sultan Süleyman döneminde inşa edilen, Osmanlı''nın akademik hiyerarşisinde en üst sıraya yerleşen ve özellikle tıp, matematik, hadis ve tabii bilimler (Darüttıb, Darülhendese) alanlarında en üst düzey ihtisas eğitimi veren yükseköğretim kurumu aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
