INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('b80d8091-0558-58c1-ae26-b7897402f34d', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Açık örgüt iklimine sahip bir okulda sadece personelin motivasyonu ve iş doyumu yüksek değildir; aynı zamanda liderin (müdürün) davranış biçimi de bu sağlıklı iklimi doğrudan besler. Halpin ve Croft''un iklim modellerine göre, ''açık iklimin'' yaşandığı bir eğitim kurumunda okul müdürünün aşağıdaki davranışlardan hangisini sergilemesi **beklenmez**?', 'PUBLISHED')
