INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('ac452e78-889a-5306-a28c-e741e90a9144', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir sınıf öğretmeni, öğrencilerinden birinin teneffüste arkadaşlarıyla yaşadığı şiddetli bir tartışmayı ve ardından gösterdiği sıra dışı bir yardımlaşma davranışını dikkatle izlemiştir. Öğretmen olayın hemen ardından kendi subjektif yorumunu katmadan, olayın geçtiği yeri, zamanı ve kişilerin eylemlerini tamamen objektif (fotoğrafik) bir şekilde bir forma kaydetmiştir. Öğretmenin kullandığı bu bireyi tanıma (gözlem) tekniği aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
