INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('d164e5f1-c0f5-5b03-9fa2-b6251ccb8182', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Derste konu anlatılırken arka sıradaki iki öğrencinin kendi aralarında fısıldaşarak konuştuğunu fark eden deneyimli bir öğretmen, dersin akışını bölmek ve bu öğrencileri sınıfın ortasında azarlamak (sözel ceza vermek) yerine; ses tonunu ve anlatımını hiç değiştirmeden yavaşça bu öğrencilerin masasına doğru yürümüş ve onların hemen yanında durarak ders anlatmaya devam etmiştir. Öğrenciler öğretmeni fark edince konuşmayı bırakmıştır. Öğretmenin uyguladığı bu örtük müdahale stratejisi nedir?', 'PUBLISHED')
