INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('1c81b43b-48cf-50bc-aef4-39d9dc0860a1', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Maslow''un İhtiyaçlar Hiyerarşisi teorisine göre, alt basamaktaki bir ihtiyaç yeterince karşılanmadan birey üst basamaktaki ihtiyaçlara güdülenemez (motive olamaz). Soğuk bir kış sabahında sınıfın ısıtma sisteminin bozulması nedeniyle çok üşüyen ve derse odaklanamayan öğrencilerin, öğretmenin sorduğu ödüllü ve eğlenceli zekâ sorusuna hiçbir ilgi göstermemesi bu durumu kanıtlar. Bu örnekte öğrencilerin karşılanmayan ve öğrenmeyi engelleyen temel ihtiyacı hangi basamakta yer alır?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
