INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('b5b69ccb-e86f-561e-90fc-41d4a0603764', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Etik bir eğitim yöneticisi, okulda alınacak önemli idari ve mali kararları gizli kapılar ardında kendi yakın çevresiyle (zümresiyle) almak yerine; kararların hangi yasal ve ahlaki gerekçelere dayandığını, okul bütçesinin kalem kalem nerelere harcandığını tüm şeffaflığıyla okul aile birliği, öğretmenler ve velilerle paylaşır. Yöneticinin eleştirilere açık olan bu şeffaf tutumu, etik liderliğin hangi temel yapı taşıyla (ilkesiyle) doğrudan ilgilidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
