INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('19ec903b-6b94-5f84-a24d-30838c68d262', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Okul bahçesindeki bitkilerin büyüme hızını inceleyen bir öğrenci grubu, araştırmanın başında ''Hangi bitki türü haftalık olarak ne kadar uzuyor?'' sorusunu sorarak veri toplama sürecini tasarlamıştır. Daha sonra yapacakları bilimsel ölçümlerde; uzama miktarını ''santimetre'' (cm) cinsinden ve toprağa verdikleri su miktarını ''mililitre'' (ml) cinsinden kayıt altına almaya (standartlaştırmaya) karar vermişlerdir. TYMM Beceriler Çerçevesi''ne göre, geçerli standartların tayin edildiği bu süreç bileşeni aşağıdakilerden hangisidir?', 'PUBLISHED')
