INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('3374a6e9-1d71-5840-9590-e4911ae2205e', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Türk-İslam devletlerinde eğitim sadece dini ve idari ilimlerle sınırlı kalmamış, uygulamalı bilimlere de büyük yatırım yapılmıştır. Anadolu Selçuklu Devleti hükümdarı I. Gıyaseddin Keyhüsrev tarafından 1204 yılında vasiyet üzerine kız kardeşi adına Kayseri''de yaptırılan; öğrencilere teorik ve pratik eğitimin bir arada (hastalar üzerinde) sunulduğu ''dünyanın ilk tıp fakültesi'' olarak kabul edilen devasa eser aşağıdakilerden hangisidir?', 'PUBLISHED')
