INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('70bc3f88-4265-5906-addc-2bf05c5fced7', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Geleneksel klinik modellerin aksine, modern ''Kapsamlı Gelişimsel Rehberlik Modeli''nde okul psikolojik danışmanı tek başına tüm yükü omuzlamaz; okul müdürü, öğretmenler ve veliler sürecin doğal birer işbirlikçisidir. Bu takım çalışması modelinde, ''sınıf içi rehberlik etkinliklerini (örneğin zaman yönetimi, verimli ders çalışma etkinlikleri vb.) planlanan müfredat dâhilinde bizzat uygulayan ve öğrencileri ilk elden tanıyarak psikolojik danışmana yönlendiren'' birincil personel aşağıdakilerden hangisidir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
