INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('f0d8f47c-6b66-5f58-900a-14ded1d7f76c', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir okulu taşıyan öğrenci servisinin karıştığı üzücü bir trafik kazasının (krizin) ardından, okul yönetimi derhal faaliyete geçerek; etkilenen öğrencilerin ailelerini hastanede ve evlerinde ziyaret etmiş, okuldaki diğer öğrenciler ve öğretmenler için Rehberlik Araştırma Merkezi''nden uzmanlar çağırarak travma sonrası psikolojik destek grupları (yas danışmanlığı) oluşturmuş ve eğitim-öğretim rutininin sağlıklı bir şekilde yeniden başlamasını sağlamıştır. Kriz yönetimi döngüsüne göre okul idaresinin yürüttüğü bu faaliyetler hangi evreye aittir?', 'PUBLISHED')
