INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('3783052f-eacb-53dc-9526-6839d165d263', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli''nin ahlaki yapısını oluşturan Erdem-Değer-Eylem (EDE) Çerçevesi, öğrencilere kazandırılacak değerlerin (saygı, sorumluluk, adalet vb.) sadece bireyin kendi içinde soyut olarak kalmamasını, dış dünyaya da olumlu bir eylem olarak yansımasını bekler. Bu doğrultuda çerçevenin nihai etki alanları üç ana hedef (katman) etrafında toplanmıştır. Aşağıdakilerden hangisi EDE Çerçevesinin tanımladığı bu üç etki alanından biridir?', 'PUBLISHED')
ON CONFLICT (id) DO UPDATE SET topic_id = excluded.topic_id, body = excluded.body, status = excluded.status;
