INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('576d74fa-b4a1-584a-b2c0-ee1e6aa18d8f', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Dersin ortalarına doğru öğrencilerin dikkatinin dağıldığını, esnemeye başladıklarını ve kendi aralarında konuşmaya yöneldiklerini fark eden bir öğretmenin, sınıfın ilgisini yeniden derse çekmek ve akademik öğrenme zamanını artırmak için yapması gereken en uygun yönetsel davranış aşağıdakilerden hangisidir?', 'PUBLISHED')
