INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('8fa06502-252b-57cd-b3d5-397e5f2c3194', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Vroom''un Beklenti Kuramı''na göre motivasyon; ''beklenti'', ''araçsallık'' ve ''valans (değer)'' unsurlarının birbiriyle çarpımı sonucunda oluşur. Bir öğretmen, okul müdürü olmayı çok istemekte (bu hedefe büyük bir değer biçmekte) ve müdür olursa bunun kendisine yüksek bir prestij sağlayacağına inanmaktadır. Ancak yapılacak olan yönetici seçme sınavının (EKYS) çok zor olduğunu ve ne kadar çalışırsa çalışsın bu sınavı geçemeyeceğini düşünmektedir. Kurama göre bu öğretmenin motivasyonunun düşmesine neden olan unsur aşağıdakilerden hangisidir?', 'PUBLISHED')
