INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('9e0d1ed4-3662-5bc2-bdbf-73f1ed017ad6', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Sınıf rehber öğretmeni, öğrencilerinin birbirlerini nasıl algıladıklarını ve sınıf içindeki belirgin karakter özelliklerini tespit etmek amacıyla üzerinde ''Sınıfın en yardımseveri kimdir?'', ''Sınıfın en iyi lideri kimdir?'', ''Sınıfın en içine kapanık öğrencisi kimdir?'' gibi soruların bulunduğu bir form dağıtmış ve öğrencilerden uygun gördükleri arkadaşlarının isimlerini yazmalarını istemiştir. Öğretmenin uyguladığı bu bireyi tanıma tekniği aşağıdakilerden hangisidir?', 'PUBLISHED')
