INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('6538ab5c-27d5-503e-bfc3-251578ed0287', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Okullarda artan dijital cihaz kullanımıyla birlikte siber zorbalık olayları da artış göstermektedir. Bir okul yönetiminin siber zorbalığı engellemek adına uygulayabileceği en etkili ''proaktif (önleyici)'' idari tedbir aşağıdakilerden hangisidir?', 'PUBLISHED')
