INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('84c17603-076f-5f01-802b-9570ad9696e8', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli Beceriler Çerçevesi''nde yer alan bir okuryazarlık türü; bireyin anayasal hak ve hürriyetlerini bilmesini, devletine ve topluma karşı sorumluluklarını yerine getirmesini (vergi bilinci, askerlik vb.), ülkesinin demokratik süreçlerine aktif katılım sağlayarak yerel ve küresel sorunlara hukuki zemin içerisinde çözüm üretmesini amaçlar. Özellikleri verilen bu okuryazarlık türü aşağıdakilerden hangisidir?', 'PUBLISHED')
