INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('143e39e9-e0b3-5639-b55a-1c7f5197c796', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir okuldaki iki zümre başkanı, fen laboratuvarının kullanım saatleri konusunda anlaşmazlığa düşmüş ve aralarında ciddi bir çatışma yaşanmıştır. Durumu fark eden okul müdürü, her iki öğretmeni de odasına davet etmiş, ihtiyaçlarını açıkça dile getirmelerini sağlamış ve taraflarla birlikte çalışarak her iki zümrenin de ders programını aksatmayacak, birlikte uyum içinde çalışacakları yepyeni bir ortak laboratuvar takvimi oluşturmuştur. Thomas-Kilmann''ın Çatışma Yönetimi Modeli''ne göre müdürün kullandığı bu strateji aşağıdakilerden hangisidir?', 'PUBLISHED')
