INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('d6937393-2be4-5cf9-aaa8-345f5eab57df', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Türkiye Cumhuriyeti''nin eğitim tarihinde; kırsal kalkınmayı sağlamak, köye aydınlanmayı götürmek ve ciddi boyutlarda olan ilkokul öğretmeni ihtiyacını karşılamak amacıyla 1940 yılında İsmail Hakkı Tonguç ve Hasan Ali Yücel''in öncülüğünde kurulan; eğitimin ''iş içinde, iş aracılığıyla ve iş için eğitim'' ilkesine dayandığı (yaparak yaşayarak öğrenme) özgün eğitim kurumları aşağıdakilerden hangisidir?', 'PUBLISHED')
