INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('4f67c5d2-83f3-5299-aab6-0d8d6fb1980f', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Sınıf yönetiminde kuralların etkinliği, öğrencilerin bu kuralları ne kadar içselleştirdiğine bağlıdır. Bir öğretmenin, eğitim öğretim yılının başında sınıf kurallarını tek başına bir liste hâlinde hazırlayıp panoya asmak yerine, öğrencileriyle birlikte bir çember oluşturarak ''Sınıfımızda daha iyi öğrenebilmek için hangi kurallara ihtiyacımız var?'' diye sorup kuralları öğrencilerle ortaklaşa belirlemesinin temel pedagojik amacı aşağıdakilerden hangisidir?', 'PUBLISHED')
