INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('07b7544a-344d-558d-8089-319ddd4a4d2d', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Lise son sınıf öğrencisi Ayşe, deneme sınavlarında sürekli başarısız olmaktan şikâyet etmekte, test çözerken zamanını yetiştiremediğini ve hangi derse ne kadar zaman ayırması (nasıl verimli çalışması) gerektiğini bilmediğini belirterek okulun rehberlik servisine başvurmuştur. Psikolojik danışmanın Ayşe''ye zaman yönetimi ve verimli çalışma alışkanlıkları konularında vereceği destek, hangi rehberlik hizmeti türünün kapsamındadır?', 'PUBLISHED')
