INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('99065073-efe8-5d20-9cd0-9e334c68b637', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli Beceriler Çerçevesi''nde yer alan ''Eğilimler'' bileşenine göre; bir öğrencinin yeni karşılaştığı olay ve durumlara ön yargısız yaklaşması, kendi dünya görüşünden farklı inanç ve düşüncelere hoşgörüyle (saygıyla) bakabilmesi, kendi sahip olduğu fikirlerin de yanlış olabileceği ihtimalini göz önünde bulundurarak sürekli bir entelektüel arayış içinde olması durumu hangi eğilim kavramıyla ifade edilir?', 'PUBLISHED')
