INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('027a2ee3-87ed-5952-8135-a044cfdd40ba', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Eğitim kurumlarında uygulanan modern liderlik yaklaşımlarından biri de, liderin asıl görevinin sadece talimat vermek değil, astlarını (öğretmenleri) kendi kendilerini yönetebilen (öz denetim sahibi), bağımsız ve yetkin bireyler hâline getirmeye çalışmasıdır. Başka bir deyişle liderin, izleyicilerinin her birinin ''kendi kendilerinin lideri'' olmasını sağlamayı hedeflediği bu yaklaşım aşağıdakilerden hangisidir?', 'PUBLISHED')
