INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('58dae1ee-b545-5f1c-95ec-1618632e3669', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir okulun sahip olduğu köklü tarihini yansıtan müzesi, kendine has tasarlanmış ve renkleri olan okul forması, bahçesindeki anıt ağacı, kuruma özel bestelenmiş okul marşı ve mezunların taktığı özel tasarım okul yüzüğü gibi görünür ve somut materyaller örgüt kültürünü yaşatan araçlardır. Örgüt kültürü literatürüne göre, kurumun kimliğini yansıtan bu nesne ve tasarımlara ne ad verilir?', 'PUBLISHED')
