INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('180fb431-cede-5ca1-9dc0-eee7dbc31264', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Özel eğitim ihtiyacı olan öğrencilerin gelişimini desteklemek amacıyla BEP Geliştirme Birimi tarafından her öğrenciye özel olarak ''Bireyselleştirilmiş Eğitim Programı (BEP)'' hazırlanır. Aşağıdakilerden hangisi BEP''in içeriğinde yer alması gereken yasal veya eğitsel unsurlardan biri **değildir**?', 'PUBLISHED')
