INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('85c65d0c-17a6-55de-ad46-33570b9c6e9c', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Okulda yaşanan ve medyaya yansıyan büyük bir acil durum/kriz anında (örneğin okulda çıkan büyük bir yangın veya kaza durumunda), kurumun itibarını korumak ve kamuoyunda telaş yaratan bilgi kirliliğini (dezenformasyon) önlemek adına okul yönetiminin kriz iletişimi bağlamında alması gereken en kritik idari önlem aşağıdakilerden hangisidir?', 'PUBLISHED')
