INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('dd122816-2ab2-5091-b83a-d0c06f47920d', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli kapsamında bir bilim projesi yürüten öğrenciler, sahadan topladıkları dağınık deney verilerini bilgisayar ortamında satır ve sütunlardan oluşan yapılandırılmış listeler (hesap tabloları) hâline getirmiş ve bu hücrelerle dinamik olarak etkileşim kurarak veriyi düzenlemişlerdir. Bu işlem, Veri Okuryazarlığı (OB7) sürecinin hangi aşamasını temsil eder?', 'PUBLISHED')
