INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('488b9414-8e17-5012-b215-301effea4afd', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Bir okul rehberlik servisi; önceki eğitim öğretim yılında liseden mezun olan, üniversiteye veya bir mesleğe yerleşen öğrencilere elektronik bir anket göndererek, kazandıkları bölümlerdeki memnuniyet durumlarını ve lisedeyken aldıkları yönlendirme hizmetinin ne derece isabetli olduğunu araştırmıştır. Yapılan bu çalışma, rehberliğin doğrudan öğrenciye sunulan hangi hizmet alanı kapsamına girer?', 'PUBLISHED')
