INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('65ac9d0a-d78c-59d2-b6d0-b97d11310353', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Osmanlı Devleti''nde Tanzimat dönemiyle birlikte geleneksel medrese sisteminin dışında, modern anlamda Avrupa tarzı bir yükseköğretim kurumu (üniversite) açılması fikri doğmuştur. Uzun süren teşebbüsler ve hazırlıklar sonucunda 1863 yılında ilk defa eğitime başlayan, ancak bilimsel ve siyasi nedenlerle defalarca kapatılıp yeniden açılan ilk modern üniversite kurumu aşağıdakilerden hangisidir?', 'PUBLISHED')
