INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('e91cc7b5-23d8-5f97-90cc-eb4a82ebf855', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Halpin ve Croft''un okul iklimi tipolojilerine göre; bir okulda okul müdürünün öğretmenlerin işini sıkı bir şekilde kontrol etmediği, okuldaki akademik hedeflerin ve standartların çok önemsenmediği, ancak öğretmenler ve idareciler arasında son derece dostane, sıcak ve yüksek bir sosyal etkileşimin bulunduğu (herkesin birbiriyle iyi anlaştığı ama görev/işin aksadığı) örgüt iklimi türü aşağıdakilerden hangisidir?', 'PUBLISHED')
