INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('188e8444-7f8a-500b-a315-2f70eb11c3f9', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Frederick Herzberg''in ''Çift Faktör Kuramı''na göre, çalışanları gerçekten motive eden ve onlara derin bir iş tatmini sağlayan faktörler (motivatörler) doğrudan işin doğasıyla (içsel süreçlerle) ilgilidir. Buna göre, aşağıdakilerden hangisi Herzberg''in tanımladığı, öğretmenin performansını kalıcı olarak artıran gerçek bir ''motivatör'' (güdüleyici) faktördür?', 'PUBLISHED')
