INSERT INTO questions (id, exam_id, topic_id, question_type, body, status) VALUES ('0173133f-e0de-5b67-ba7f-59abfd394397', '27372eac-908b-54d8-b8f9-77b260c7d060', '0800dcf0-57ab-5d19-acf9-d813ada85484', 'SINGLE_CHOICE', 'Türkiye Yüzyılı Maarif Modeli Sosyal-Duygusal Öğrenme (SDÖ) Becerilerinde ''Benlik Becerileri'' önemli bir yer tutar. Bir öğrencinin, öfkelendiğinde kendisine veya başkasına zarar verebilecek anlık dürtülerini erteleyebilmesi, uzun vadeli hedeflerine ulaşmak için zamanını ve stresini doğru yönetmesi (kendi davranışlarını ve duygularını kontrol altına alması) aşağıdaki beceri süreçlerinden hangisiyle ifade edilir?', 'PUBLISHED')
